import React, { useState } from 'react'
import { useTranslation } from 'react-i18next'
import useLocaleTranslation from '@common/hooks/useLocaleTranslation'
import { isReadServerTextData } from '@common/constants/env'
import { ViewEnum } from '@/constants/viewSwitch'
import './index.less'

interface ViewSwitchProps {
  title?: string | React.ReactNode
  canAdminUserView?: boolean
  isUser?: any
  setIsUser?: any
  canHeadUserView?: boolean
  type?: any
  viewEnum?: any
  setViewEnum?: any
  canInitiativeCreatorView?: any
}

// 视图切换组件：
// 根据角色权限(canAdminUserView/canHeadUserView)与页面类型(type)渲染不同的视图选项，
// 并通过 setIsUser / setViewEnum 将用户选择回传给父组件。
const ViewSwitch: React.FC<ViewSwitchProps> = (props) => {
  const {
    title,
    canAdminUserView,
    isUser,
    setIsUser,
    canHeadUserView,
    type,
    viewEnum,
    setViewEnum,
    canInitiativeCreatorView,
  } = props
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['project'])

  // 管理员与普通用户的双视图切换（非 project 场景使用 isUser 布尔值控制）
  const canAdminUserViewDataList = [
    { id: ViewEnum.AdminView, text: t('project:viewSwitch.adminView') },
    { id: ViewEnum.UserView, text: t('project:viewSwitch.userView') },
  ]
  // project 场景下管理员可切换的三视图（PM / Admin / User）
  const canAdminUserViewPmDataList = [
    { id: ViewEnum.OwnerView, text: t('project:viewSwitch.pmView') },
    { id: ViewEnum.AdminView, text: t('project:viewSwitch.adminView') },
    { id: ViewEnum.UserView, text: t('project:viewSwitch.userView') },
  ]
  // initiative
  const canAdminUserViewInitiativeDataList = [
    { id: ViewEnum.CreatorView, text: t('initiatives:creatorView') },
    { id: ViewEnum.AdminView, text: t('project:viewSwitch.adminView') },
    { id: ViewEnum.UserView, text: t('project:viewSwitch.userView') },
  ]

  // project 场景下普通用户可切换的双视图（User / PM）
  const UserDataList = [
    { id: ViewEnum.UserView, text: t('project:viewSwitch.userView') },
    { id: ViewEnum.OwnerView, text: t('project:viewSwitch.pmView') },
  ]
  //当用户仅是 creator
  const initiativeCreatorDataList = [
    { id: ViewEnum.CreatorView, text: t('initiatives:creatorView') },
    { id: ViewEnum.UserView, text: t('project:viewSwitch.userView') },
  ]

  // 负责人(head)在非 project 场景下的双视图（Sector / User）
  const sectorList = [
    { id: ViewEnum.SectorView, text: t('project:viewSwitch.sectorView') },
    { id: ViewEnum.UserView, text: t('project:viewSwitch.userView') },
  ]

  // 负责人(head)在 project 场景下的三视图（PM / Sector / User）
  const pmSectorList = [
    { id: ViewEnum.OwnerView, text: t('project:viewSwitch.pmView') },
    { id: ViewEnum.SectorView, text: t('project:viewSwitch.sectorView') },
    { id: ViewEnum.UserView, text: t('project:viewSwitch.userView') },
  ]
  const initiativeSectorList = [
    { id: ViewEnum.CreatorView, text: t('initiatives:creatorView') },
    { id: ViewEnum.SectorView, text: t('project:viewSwitch.sectorView') },
    { id: ViewEnum.UserView, text: t('project:viewSwitch.userView') },
  ]

  const handleClick = (index) => {
    if (index != 0) {
      setIsUser(true)
    } else {
      setIsUser(false)
    }
  }

  // project 场景的点击处理：
  // 该模式下父组件直接保存完整的 viewEnum（如 Owner/Admin/User/Sector），
  // 这里将当前点击项的 id 原样透传给父组件。
  const handleViewEnum = (index) => {
    setViewEnum(index)
  }
  return (
    <div className='view-switch'>
      <div>{title}</div>
      <div className='view-switch-container'>
        {
          // 负责人可见分支：
          // project 用 viewEnum 精确匹配；非 project 用 isUser 布尔值判断选中态。
          canHeadUserView &&
            (type == 'project' ? (
              <div className='view-switch-content-pm'>
                {pmSectorList.map((item, index) => {
                  return (
                    <div
                      className={
                        item.id == viewEnum ? 'selected' : 'content-pm-item'
                      }
                      key={index}
                      onClick={() => handleViewEnum(item.id)}
                    >
                      {item.text}
                    </div>
                  )
                })}
              </div>
            ) : type == 'initiative' ? (
              <div className='view-switch-content-pm'>
                {initiativeSectorList.map((item, index) => {
                  return (
                    <div
                      className={
                        item.id == viewEnum ? 'selected' : 'content-pm-item'
                      }
                      key={index}
                      onClick={() => handleViewEnum(item.id)}
                    >
                      {item.text}
                    </div>
                  )
                })}
              </div>
            ) : (
              <div className='view-switch-content'>
                {sectorList.map((item, index) => {
                  return (
                    <div
                      className={
                        (item.id == ViewEnum.UserView ? isUser : !isUser)
                          ? 'selected'
                          : 'view-switch-content-item'
                      }
                      key={index}
                      onClick={() => handleClick(index)}
                    >
                      {item.text}
                    </div>
                  )
                })}
              </div>
            ))
        }
        {/* 管理员可见分支：project 与非 project 分别沿用两种状态模型（viewEnum / isUser） */}
        {canAdminUserView &&
          (type == 'project' ? (
            <div className='view-switch-content-pm'>
              {canAdminUserViewPmDataList.map((item, index) => {
                return (
                  <div
                    className={
                      item.id == viewEnum ? 'selected' : 'content-pm-item'
                    }
                    key={index}
                    onClick={() => handleViewEnum(item.id)}
                  >
                    {item.text}
                  </div>
                )
              })}
            </div>
          ) : type == 'initiative' ? (
            <div className='view-switch-content-pm'>
              {canAdminUserViewInitiativeDataList.map((item, index) => {
                return (
                  <div
                    className={
                      item.id == viewEnum ? 'selected' : 'content-pm-item'
                    }
                    key={index}
                    onClick={() => handleViewEnum(item.id)}
                  >
                    {item.text}
                  </div>
                )
              })}
            </div>
          ) : (
            <div className='view-switch-content'>
              {canAdminUserViewDataList.map((item, index) => {
                return (
                  <div
                    className={
                      (item.id == ViewEnum.UserView ? isUser : !isUser)
                        ? 'selected'
                        : 'view-switch-content-item'
                    }
                    key={index}
                    onClick={() => handleClick(index)}
                  >
                    {item.text}
                  </div>
                )
              })}
            </div>
          ))}

        {/* 无管理员/负责人权限时，project 场景默认展示普通用户可选的 User/PM 双视图 */}
        {!canAdminUserView && !canHeadUserView && type == 'project' && (
          <div className='view-switch-content'>
            {UserDataList.map((item, index) => {
              return (
                <div
                  className={
                    item.id == viewEnum
                      ? 'selected'
                      : 'view-switch-content-item'
                  }
                  key={index}
                  onClick={() => handleViewEnum(item.id)}
                >
                  {item.text}
                </div>
              )
            })}
          </div>
        )}
        {canInitiativeCreatorView && !canAdminUserView && !canHeadUserView && (
          <div className='view-switch-content'>
            {initiativeCreatorDataList.map((item, index) => {
              return (
                <div
                  className={
                    item.id == viewEnum
                      ? 'selected'
                      : 'view-switch-content-item'
                  }
                  key={index}
                  onClick={() => handleViewEnum(item.id)}
                >
                  {item.text}
                </div>
              )
            })}
          </div>
        )}
      </div>
    </div>
  )
}
export default ViewSwitch

import { useCallback, useEffect, useRef, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { useTranslation } from 'react-i18next'
import {
  Button,
  Form,
  Input,
  InputNumber,
  Link,
  Message,
  Select,
  Tooltip,
} from '@arco-design/web-react'
import {
  IconDelete,
  IconEdit,
  IconEye,
  IconPlus,
} from '@arco-design/web-react/icon'
import { useLocalStorageState, useRequest, useSetState } from 'ahooks'
import PageWrapper from '@common/components/PageWrapper'
import ListFilterForm from '@common/components/ListFilterForm'
import UnifiedTableStyle from '@common/components/UnifiedTableStyle'
import ViewSwitch from '@common/components/ViewSwitch'
import useLocaleTranslation from '@common/hooks/useLocaleTranslation'
import { isReadServerTextData } from '@common/constants/env'
import { ViewEnum } from '@/constants/viewSwitch'
import { getTeamsList, deleteTeam, getUserList } from '@/service'
import ChooseTeamTypeModal, { TeamType } from './components/ChooseTeamTypeModal'
import { TeamStatusEnum, TeamTypeEnum } from '@/constants/committee'
import './index.less'
import TeamDeleteModal from './TeamDeleteModal'
import useDebouncedPromise from '@common/hooks/useDebouncedPromise'
import { getLanguage } from '@common/utils/localStorage'
import { LanguageEnum } from '@common/constants/language'
import { renderEllipsisText } from '@common/components/EllipsisText'
import UserIcon from '@/assets/images/committee/user-icon.svg?react'
import dayjs from 'dayjs'
import { CommitteePermissionEnum } from '@/constants/permission'
import useCheckPermission from '@common/hooks/useCheckPermission'
import { userViewStorageKey } from '@common/constants/localStorageKey'

const FormItem = Form.Item
const Option = Select.Option

const Teams = () => {
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation([
        'common',
        'committee',
        'formula',
        'membersDepartments',
        'project',
        'cycle',
        'historyLog',
        'dashboard',
        'reports',
      ])
  const checkPermission = useCheckPermission()
  const canAdminUserView = checkPermission(
    CommitteePermissionEnum.CommitteeAdminView,
  )
  const [isUser, setIsUser] = useLocalStorageState<any>(userViewStorageKey, {
    defaultValue: false,
  })

  const canAddTeam = checkPermission(CommitteePermissionEnum.TeamAdd)
  const canDeleteTeam = checkPermission(CommitteePermissionEnum.TeamDelete)
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const navigate = useNavigate()
  const formRef = useRef(null)
  const tableRef = useRef(null)

  const [chooseTypeVisible, setChooseTypeVisible] = useState(false)
  const [deleteModalVisible, setDeleteModalVisible] = useState(false)
  const [teamId, setTeamId] = useState('')
  const [filterTeamParams, setFilterTeamParams] = useSetState({
    pageNum: 1,
    pageSize: 20,
    keyword: '',
    ownerId: '',
    status: '',
    type: '',
    decisionNumber: null,
  })
  const [userList, setUserList] = useState([])

  const teamTypeOptions = [
    {
      label: t('committeeTeam:teams.teamType.committee'),
      value: TeamTypeEnum.Committee,
    },
    {
      label: t('committeeTeam:teams.teamType.workingGroup'),
      value: TeamTypeEnum.WorkingGroup,
    },
  ]

  const statusOptions = [
    {
      label: t('cycle:status.drafts'),
      value: TeamStatusEnum.STATUS_DRAFT,
    },
    {
      label: t('cycle:status.published'),
      value: TeamStatusEnum.STATUS_PUBLISHED,
    },
  ]

  const getStatusTag = (status: number) => {
    if (status === TeamStatusEnum.STATUS_DRAFT) {
      return (
        <span className='team-status draft'>{t('cycle:status.drafts')}</span>
      )
    }
    return (
      <span className='team-status publish'>{t('cycle:status.published')}</span>
    )
  }

  const handleAdd = () => {
    setChooseTypeVisible(true)
  }

  const handleChooseTypeConfirm = (teamType: TeamType) => {
    setChooseTypeVisible(false)
    navigate(`/committee/teams/add/${encodeURIComponent(teamType)}`)
  }

  const handleChooseTypeCancel = () => {
    setChooseTypeVisible(false)
  }

  const handleEdit = (teamId: number) => {
    navigate(`/committee/teams/edit/${teamId}`)
  }

  const handleDetail = (teamId: number) => {
    navigate(`/committee/teams/detail/${teamId}`)
  }

  const handleTeamDelete = (teamId: string) => {
    setDeleteModalVisible(true)
    setTeamId(teamId)
  }

  const debouncedDeleteTeam = useDebouncedPromise(deleteTeam, 500)
  const { loading: deleteLoading, runAsync: runDeleteTeam } = useRequest(
    debouncedDeleteTeam,
    {
      manual: true,
      onSuccess: () => {
        Message.success(t('common:message.deleteSuccessfully'))
        tableRef.current?.refresh()
      },
    },
  )

  const setDeleteVisible = (status: boolean, flag: string) => {
    setDeleteModalVisible(status)
    if (flag === 'ok') {
      runDeleteTeam({ teamId })
    } else {
      setTeamId('')
    }
  }

  // get all user list
  const { run: getAllUserList } = useRequest(getUserList, {
    manual: true,
    onSuccess(data: any, params) {
      const userOptions = data.map((item) => {
        return {
          label: isLanguageAR ? item.fullNameAr : item.fullName,
          value: item.userId,
        }
      })

      setUserList(userOptions || [])
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })

  useEffect(() => {
    getAllUserList({ pageNum: 1, pageSize: 10000 })
  }, [])

  const columns = [
    {
      title: t('committeeTeam:teams.columns.team'),
      dataIndex: 'name',
      width: 260,
      render: (_: any, record: any) => {
        const teamName = isLanguageAR ? record.nameAr : record.name
        const displayName =
          record.decisionNumber != null
            ? `${teamName}  #${record.decisionNumber}`
            : teamName
        return renderEllipsisText(displayName)
      },
    },
    {
      title: t('formula:columns.type'),
      dataIndex: 'type',
      width: 180,
      render: (_: any, record: any) => {
        const label =
          record.type === TeamTypeEnum.WorkingGroup
            ? t('committeeTeam:teams.teamType.workingGroup')
            : t('committeeTeam:teams.teamType.committee')
        return renderEllipsisText(label)
      },
    },
    {
      title: t('committeeTeam:teams.columns.owner'),
      dataIndex: 'managersDetail',
      width: 200,
      render: (_: any, record: any) => {
        const manager = record.managersDetail?.[0]
        const name = isLanguageAR ? manager?.nameAr : manager?.name
        return (
          <div className='teams-list-owner'>
            <UserIcon style={{ width: '24px', height: '24px' }} />
            <span>{name || '-'}</span>
          </div>
        )
      },
    },
    {
      title: t('membersDepartments:btn.members'),
      dataIndex: 'teamMemberNumber',
      width: 120,
    },
    {
      title: t('project:startDate'),
      dataIndex: 'startDate',
      width: 160,
      sorter: (a: any, b: any) =>
        dayjs(a.startDate, 'DD/MM/YYYY').valueOf() -
        dayjs(b.startDate, 'DD/MM/YYYY').valueOf(),
      render: (value: string) => renderEllipsisText(value || '—'),
    },
    {
      title: t('project:endDate'),
      dataIndex: 'endDate',
      width: 160,
      sorter: (a: any, b: any) =>
        dayjs(a.endDate, 'DD/MM/YYYY').valueOf() -
        dayjs(b.endDate, 'DD/MM/YYYY').valueOf(),
      render: (value: string) => renderEllipsisText(value || '—'),
    },
    {
      title: t('committeeTeam:teams.columns.decisionNumber'),
      dataIndex: 'decisionNumber',
      width: 160,
      sorter: (a: any, b: any) =>
        (a.decisionNumber ?? -1) - (b.decisionNumber ?? -1),
      render: (value: number) =>
        renderEllipsisText(value != null ? String(value) : '—'),
    },
    {
      title: t('common:columns.status'),
      dataIndex: 'status',
      width: 160,
      render: (value: number) => getStatusTag(value),
    },
    {
      title: t('common:columns.action'),
      dataIndex: 'action',
      fixed: 'right' as const,
      width: 100,
      render: (_: any, record: any) => (
        <div className='teams-list-action'>
          {record.status === TeamStatusEnum.STATUS_DRAFT ? (
            <Tooltip content={t('common:btn.edit')}>
              <Link
                className={`action-style-button`}
                icon={<IconEdit />}
                onClick={() => handleEdit(record.teamId)}
              />
            </Tooltip>
          ) : (
            <Tooltip content={t('common:btn.detail')}>
              <Link
                className={`action-style-button`}
                icon={<IconEye />}
                onClick={() => handleDetail(record.teamId)}
              />
            </Tooltip>
          )}
          {canDeleteTeam && (
            <Tooltip content={t('common:btn.delete')}>
              <Link
                className={`action-delete-button`}
                icon={<IconDelete />}
                onClick={() => handleTeamDelete(record.teamId)}
              />
            </Tooltip>
          )}
        </div>
      ),
    },
  ]

  const getList = useCallback(
    (p) => {
      return getTeamsList({
        ...p,
        ...filterTeamParams,
        userView: isUser ? ViewEnum.UserView : ViewEnum.AdminView,
      }).then((res: any) => {
        return res || []
      })
    },
    [filterTeamParams, isUser],
  )

  return (
    <PageWrapper
      headerTitle={
        <ViewSwitch
          title={t('committeeTeam:teams.title')}
          canAdminUserView={canAdminUserView}
          setIsUser={setIsUser}
          isUser={isUser}
        />
      }
    >
      <ListFilterForm
        ref={formRef}
        showResetBtn={true}
        showSettingBtn={false}
        renderBtnJsx={
          canAddTeam ? (
            <Button
              type='text'
              className='button-size-small'
              icon={<IconPlus style={{ fill: '#fff' }} />}
              onClick={handleAdd}
            >
              {t('committeeTeam:teams.addTeam')}
            </Button>
          ) : null
        }
        onSubmit={(values) => {
          const search = {
            keyword: values?.keyword,
            ownerId: values?.ownerId,
            status: values?.status,
            type: values?.type,
            decisionNumber: values?.decisionNumber ?? '',
          }
          setFilterTeamParams(search)
          tableRef.current?.refresh()
        }}
        onReset={() => {
          setFilterTeamParams({
            pageNum: 1,
            pageSize: 20,
            keyword: '',
            ownerId: '',
            status: '',
            type: '',
            decisionNumber: '',
          })
          formRef.current?.resetForm()
          tableRef.current?.refresh()
        }}
      >
        <FormItem field='keyword'>
          <Input placeholder={t('common:searchPlaceholder')} allowClear />
        </FormItem>
        <FormItem field='type'>
          <Select
            placeholder={t('committeeTeam:teams.addTeamForm.teamType')}
            allowClear
            style={{ width: 200 }}
            onChange={(value) => setFilterTeamParams({ type: value })}
          >
            {teamTypeOptions.map((opt) => (
              <Option key={opt.value} value={opt.value}>
                {opt.label}
              </Option>
            ))}
          </Select>
        </FormItem>
        <FormItem field='ownerId'>
          <Select
            allowClear
            showSearch
            placeholder={t('common:pleaseSelect')}
            onChange={(value) => setFilterTeamParams({ ownerId: value })}
            filterOption={(inputValue, option) =>
              option.props.children
                .toLowerCase()
                .includes(inputValue.toLowerCase())
            }
            style={{ width: 200 }}
          >
            {userList.map((option) => (
              <Option
                key={option.value}
                value={option.value}
                extra={option.orgInfoList}
              >
                {option.label}
              </Option>
            ))}
          </Select>
        </FormItem>
        {canAddTeam && (
          <FormItem field='status'>
            <Select
              placeholder={t('membersDepartments:columns.status')}
              allowClear
              style={{ width: 200 }}
              onChange={(value) => setFilterTeamParams({ status: value })}
            >
              {statusOptions.map((opt) => (
                <Option key={opt.value} value={opt.value}>
                  {opt.label}
                </Option>
              ))}
            </Select>
          </FormItem>
        )}
        <FormItem field='decisionNumber'>
          <InputNumber
            precision={0}
            min={0}
            placeholder={t('committeeTeam:teams.columns.decisionNumber')}
            style={{ width: 200 }}
            onChange={(value) =>
              setFilterTeamParams({ decisionNumber: value ?? '' })
            }
          />
        </FormItem>
      </ListFilterForm>

      <UnifiedTableStyle
        ref={tableRef}
        rowKey='id'
        showNoColumn={false}
        noColumnWidth={80}
        columns={columns}
        loading={true}
        getList={getList}
        className={'teams-table'}
        onChange={(pagination) => {
          setFilterTeamParams({ pageNum: pagination.current })
        }}
      />
      {chooseTypeVisible && (
        <ChooseTeamTypeModal
          visible={chooseTypeVisible}
          onConfirm={handleChooseTypeConfirm}
          onCancel={handleChooseTypeCancel}
        />
      )}
      {deleteModalVisible && (
        <TeamDeleteModal
          deleteModalVisible={deleteModalVisible}
          setDeleteVisible={setDeleteVisible}
          loading={deleteLoading}
        />
      )}
    </PageWrapper>
  )
}

