      >
        <div>
          <PieChart
            performance={roundDown(progress, true)}
            actualOfDate={actualOfDate}
            measurementMechanism={measurementMechanism}
            unitType={unitType}
            formulas={formulas}
            type={type}
            averageOfDate={averageOfDate}
          />
        </div>
      </Popover>
    )
  }

  const columnsData: TableColumnProps[] = [
    {
      title: t('kpis:list.column.name'),
      dataIndex: 'kpiName',
      width: 310,
      render: (_, record) => {
        const paperclip =
          record?.processAttachmentFlag ==
          kpiProcessAttachmentFlagEnum.HasFiles ? (
            <Tooltip content={record?.processAttachmentFiles?.[0]?.fileName}>
              <span style={{ color: '#86909c', display: 'inline-flex' }}>
                <IconAttachment />
              </span>
            </Tooltip>
          ) : null


        return cycleClosed(record?.cycleStatus) ? (
          <div
            style={{ cursor: 'pointer', display: 'flex', alignItems: 'center' }}
          >
            <Badge
              color={getDaysAgo(record.lastUpdateTime)}
              style={isLanguageAR ? { marginLeft: 6 } : { marginRight: 6 }}
            ></Badge>
            {renderEllipsisText(record.kpiName)}
            {paperclip}
          </div>
        ) : (
          <div
            onClick={() =>
              jumpToDetailsPage({
                type: 'kpis',
                id: record.kpiInfoId,
                navigate,
                record,
              })
            }
            style={{ cursor: 'pointer', display: 'flex', alignItems: 'center' }}
          >
            <Badge
              color={getDaysAgo(record.lastUpdateTime)}
              style={isLanguageAR ? { marginLeft: 6 } : { marginRight: 6 }}
            ></Badge>
            {renderEllipsisText(record.kpiName, underline())}
            {paperclip}
          </div>
        )
      },
