const TopLeftBtn = (props) => {
  const navigate = useNavigate()
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['common', 'activities', 'initiatives'])
  const ActivitiesChart = () => {
    navigate('/initiatives/activities/charts')
  }

  const { run: exportActivitiesList, loading: exportActivitiesListLoading } =
    useRequest(exportInitiativeActivitiesList, {
      manual: true,
      onSuccess: (res: any) => {
        if (res) {
          const fileName = `${t('activities:activitiesList')}-${dayjs().valueOf()}.xlsx`
          downloadFile(res.data, fileName)
        }
      },
    })

  const [downloadDisable, setDownloadDisable] = useState(false)
  useEffect(() => {
    const result =
      _.isEmpty(props.pageSize) ||
      props.pageSize == 0 ||
      exportActivitiesListLoading
    setDownloadDisable(result)
  }, [props.pageSize])
  return (
    <div>
      <Link
        icon={<ViewChartIcon />}
        className='coc-table-link'
        onClick={ActivitiesChart}
      >
        {t('activities:btn.viewChart')}
      </Link>
      <span style={{ margin: '0 10px', color: '#E5E6EB' }}>|</span>
      <Link
        icon={
          exportActivitiesListLoading ? (
            <IconLoading />
          ) : (
            <IconExport style={{ transform: 'rotate(-90deg)' }} />
          )
        }
        className='coc-table-link'
        disabled={downloadDisable}
        onClick={() => exportActivitiesList(props)}
      >
        {t('common:btn.export')}
      </Link>
    </div>
  )
}

const ActivitiesList = () => {
  const tableRef = useRef(null)
  const navigate = useNavigate()
  const { activitySearch, setActivitySearchInfo } = useActivity()
  const [activityFilterParams, setActivityFilterParams] =
    useSetState<activitySearchState>(activitySearchInitData)
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['common', 'activities'])
  const ActivitiesDetails = (activityId) => {
    navigate(`/initiatives/activities/details/${activityId}`)
  }

  const measurementTypesEnum = {
    0: t('activities:increasingBetter'),
    1: t('activities:decreasingBetter'),
  }
  const getProgressDetailRate = (record) => {
    const progress = +record.completionOfDate
    const actualOfDate = +record.actualOfDate
    const targetOfDate = +record.targetOfDate
    return (
      <Popover
        content={
          <div style={{ display: 'flex', flexDirection: 'column' }}>
            <p style={{ display: 'inline-flex', gap: '10px' }}>
              <span>{t('activities:columns.avtual')}</span>:
              <span>{actualOfDate}</span>
            </p>
            <p style={{ display: 'inline-flex', gap: '10px' }}>
              <span>{t('activities:columns.target')}</span>:
              <span>{targetOfDate}</span>
            </p>
            <p style={{ display: 'inline-flex', gap: '10px' }}>
              <span>{t('strategicObjectives:columns.measurementTypes')}</span>:
              <span>
                {record.measurementType ==
                  measurementTypeEnum['Increasing Better'] ||
                record.measurementType ==
                  measurementTypeEnum['Decreasing Better']
                  ? measurementTypesEnum[record.measurementType]
                  : '--'}
              </span>
            </p>
          </div>
        }
      >
        <Progress
          percent={roundDown(progress)}
          color={getProgressColor(progress)}
        />
      </Popover>
    )
  }
  const columnsData: TableColumnProps[] = [
    {
      title: t('activities:columns.initiatives'),
      dataIndex: 'initiativeName',
      width: 150,
      render: (_, record) => {
        return (
          // record.initiativeStatus === InitiativesStatus.Published ? (
          <div
            onClick={() =>
              jumpToDetailsPage({
                type: 'activities',
                id: record.initiativePrimaryId,
                navigate,
                record,
              })
            }
            style={{ cursor: 'pointer' }}
          >
            {renderEllipsisText(record.initiativeName, underline())}
          </div>
          // ) : (
          //   <span style={{ padding: '1px 4px' }}>{record.initiativeName}</span>
          // ),
        )
      },
    },
    {
      title: t('activities:columns.activityTitle'),
      dataIndex: 'name',
      width: 150,
      render: renderEllipsisText,
    },
    {
      title: t('activities:columns.target'),
      dataIndex: 'target',
      width: 150,
      render: renderEllipsisText,
    },
    {
      title: t('activities:columns.activityCompletionRate'),
      dataIndex: 'completionOfDate',
      width: 200,
      render: (_, record) => {
        return getProgressDetailRate(record)
      },
    },

    {
      title: t('activities:columns.activityStartDate'),
      dataIndex: 'planedStartDate',
      width: 200,
      render: renderEllipsisText,
    },
    {
      title: t('activities:columns.activityDueDate'),
      dataIndex: 'planedEndDate',
      width: 200,
      render: renderEllipsisText,
    },
    {
      title: t('activities:columns.responsibleEmployee'),
      dataIndex: 'responsiblePersonList',
      width: 190,
      render: (_, record) => {
        const responsiblePersonName = record.responsiblePersonList
          ?.map((item) => (isLanguageAR ? item?.nameAr : item?.name))
          .join(', ')
        return <ActivitiesAvatar name={responsiblePersonName} />
      },
    },
    {
      title: t('common:columns.action'),
      fixed: 'right',
      dataIndex: 'action',
      width: 80,
      render: (_, record) => (
        <div>
          {record.initiativeStatus === InitiativesStatus.Published &&
            useConditionalButton(
              <Tooltip content={t('activities:btn.details')}>
                <Link
                  icon={<IconUpload />}
                  className='coc-table-link'
                  onClick={() => ActivitiesDetails(record.activityId)}
                />
              </Tooltip>,
              record?.cycleStatus,
            )}
        </div>
      ),
    },
  ]
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const [cycleList, setCycleList] = useState([])
  const formRef = useRef(null)
  const [total, setTotal] = useState(0)
  const [selectCycleId, setSelectCycleId] = useState('id')
  //搜索框数据
  const [initiativesOwnerData, setInitiativesOwnerData] = useState<any>([])
  const [departmentData, setDepartmentData] = useState<any>([])

  const checkPermission = useCheckPermission()
  const canAdminUserView = checkPermission(
    InitiativePermissionEnum.ActivityAdminUserView,
  )
  const headUserView = checkPermission(
    InitiativePermissionEnum.ActivityHeadUserView,
  )
  const canHeadUserView =
    canAdminUserView && headUserView ? false : headUserView
  const [isUser, setIsUser] = useLocalStorageState<any>(userViewStorageKey, {
    defaultValue: false,
  })
  const location = useLocation()
  // 查询cycle列表
  const { run: getCycleByNowTime } = useRequest(getCylceByTime, {
    manual: true,
    onSuccess(data: any, params) {
      const cycleOptions = data.map((item) => ({
        label: isLanguageAR ? item.cycleNameAr : item.cycleName,
        value: item.id,
      }))
      const nowCycleId =
        _.isEmpty(activitySearch.cycleId) || _.isEmpty(location.state)
          ? cycleOptions[0].value
          : activitySearch.cycleId
      formRef.current?.setFormItemValue('cycleId', nowCycleId)
      formRef.current?.setFormItemValue('keyword', activitySearch.keyword)
      formRef.current?.setFormItemValue(
        'activitiesDate',
        activitySearch.activitiesDate,
      )
      formRef.current?.setFormItemValue('orgId', activitySearch.orgId)
      formRef.current?.setFormItemValue(
        'responsiblePersonId',
        activitySearch.responsiblePersonId || undefined,
      )
      formRef.current?.setFormItemValue(
        'ownerId',
        activitySearch.ownerId || undefined,
      )
      setCycleList(cycleOptions || [])
      setSelectCycleId(nowCycleId)
      setActivitySearchInfo({
        ...activitySearch,
        cycleId: nowCycleId,
      })
      setActivityFilterParams({
        cycleId: nowCycleId,
      })
      // 点击左侧菜单
      if (_.isEmpty(location.state)) {
        setActivitySearchInfo({
          ...activitySearchInitData,
          cycleId: nowCycleId,
          keyword: '',
        })
        setActivityFilterParams({
          ...activitySearchInitData,
          cycleId: nowCycleId,
          keyword: '',
        })
        setTimeout(() => {
          formRef.current?.setFormItemValue('keyword', '')
          formRef.current?.setFormItemValue('activitiesDate', [])
          formRef.current?.setFormItemValue('orgId', undefined)
          formRef.current?.setFormItemValue('responsiblePersonId', undefined)
          formRef.current?.setFormItemValue('ownerId', undefined)
        }, 10)
      }
      getOrgTree({ cycleId: nowCycleId })
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })

  //获取initiativesOwner
  const { run: getAllUserList } = useRequest(getUserList, {
    manual: true,
    onSuccess(data: any, params) {
      const userOptions = data.map((item) => ({
        label: isLanguageAR
          ? `${item.fullNameAr}(${getMailString(item.mail)})`
          : `${item.fullName}(${getMailString(item.mail)})`,
        value: item.userId,
      }))
      setInitiativesOwnerData(userOptions || [])
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })

  //获取department 列表
  const { run: getOrgTree } = useRequest(getOrgTreeRecursion, {
    manual: true,
    onSuccess(res: any, params) {
      const data = transformData(res, t)
      setDepartmentData(data || [])
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })

  useEffect(() => {
    getCycleByNowTime()
    getAllUserList({ pageNum: 1, pageSize: 9999 })
    getProjectTableConfig(TableBizType.Activity)
  }, [])
  //获取表格数据
  const getList = useCallback(
    (
      page: { pageNum: number; pageSize: number } = {
        pageNum: activitySearch.pageNum,
        pageSize: activitySearch.pageSize,
      },
    ) => {
      if (selectCycleId === 'id') {
        return Promise.resolve({ list: [], total: 0 })
      }
      const allSearchFields = {
        keyword: activitySearch.keyword,
        cycleId: activitySearch.cycleId,
        userView: isUser,
        orgId: activitySearch.orgId,
        responsiblePersonId: activitySearch.responsiblePersonId ?? '',
        ownerId: activitySearch.ownerId ?? '',
        startTime: activitySearch?.activitiesDate?.[0] || '',
        endTime: activitySearch?.activitiesDate?.[1] || '',
        ...page,
        pageNum: activitySearch.pageNum,
      }
      return getActivitiesList(allSearchFields).then((res: any) => {
        const activitiesList = res?.list || []
        res.list = activitiesList.map((item) => {
          return {
            ...item,
            addedBy: isLanguageAR ? item.addedBy?.nameAr : item.addedBy?.name,
            initiativeName: isLanguageAR
              ? item.initiativeNameAr
              : item.initiativeName,
          }
        })
        setTotal(res?.total)
        return {
          list: res?.list,
          total: res?.total,
          pageNum: activitySearch.pageNum,
          pageSize: activitySearch.pageSize,
        }
      })
    },

    [activityFilterParams, location],
  )
  const handleSelectChange = (value) => {
    setActivitySearchInfo({
      ...activitySearch,
      cycleId: value,
      orgId: '',
      pageNum: 1,
    })
    setActivityFilterParams({ cycleId: value, orgId: '', pageNum: 1 })
    getOrgTree({ cycleId: value })
    tableRef.current?.refresh()
  }

  const departmentNameChange = (value) => {
    setActivitySearchInfo({
      ...activitySearch,
      orgId: value,
      pageNum: 1,
    })
    setActivityFilterParams({
      orgId: value,
      pageNum: 1,
    })
    tableRef.current?.refresh()
  }
  const initiativesResponsiblePersonChange = (value) => {
    setActivitySearchInfo({
      ...activitySearch,
      responsiblePersonId: value,
      pageNum: 1,
    })
    setActivityFilterParams({
      responsiblePersonId: value,
      pageNum: 1,
    })
    tableRef.current?.refresh()
  }
  const initiativesOwnerChange = (value) => {
    setActivitySearchInfo({
      ...activitySearch,
      ownerId: value,
      pageNum: 1,
    })
    setActivityFilterParams({
      ownerId: value,
      pageNum: 1,
    })
    tableRef.current?.refresh()
  }
  useEffect(() => {
    setActivitySearchInfo({ ...activitySearch, userView: isUser })
    setActivityFilterParams({ userView: isUser })
    tableRef.current?.refresh()
  }, [isUser])

  useEffect(() => {
    // tableRef.current.refresh()
    tableRef.current?.setPageNum(activitySearch.pageNum)
  }, [activityFilterParams])

  const tableChange = (pagination, sorter, filters) => {
    setActivitySearchInfo({
      ...activitySearch,
      pageNum: pagination.current,
    })
    setActivityFilterParams({ pageNum: pagination.current })
  }

  const [columns, setColumns] = useState([])
  //渲染checkbox组件的数据
  const [columnsSetting, setColumnsSetting] = useState([])
  const [visibleColumnsDataIndex, setVisibleColumnsDataIndex] = useState([])
  const [columnsFromServer, setColumnsFromServer] = useState([])
  const [actionData, setActionData] = useState([])
  const [popVisible, setPopVisible] = useState(false)

  const { run: getProjectTableConfig } = useRequest(getUserTableHeaderConfig, {
    manual: true,
    onSuccess(data: any, params) {
      const getColumnsFromServer = JSON.parse(data) ?? []
      if (!_.isEmpty(getColumnsFromServer)) {
        const columnServerData = columnsData.filter((item) =>
          getColumnsFromServer.includes(item.dataIndex as string),
        )
        setColumnsFromServer(getColumnsFromServer)
        setColumns(columnServerData)
        setVisibleColumnsDataIndex(getColumnsFromServer)
      } else {
        const visibleColumnsDataIndex = columnsData
          .filter((v) => v.dataIndex !== 'action')
          .map((m) => m.dataIndex as string)
        setTimeout(() => {
          setColumns(columnsData)
        }, 10)
        setColumnsFromServer(visibleColumnsDataIndex)
      }
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })
  useEffect(() => {
    // 需要配置的字段
    const columnsSettingData = columnsData
      .filter((m) => m.dataIndex !== 'action')
      .map((v) => ({ key: v.dataIndex as string, title: v.title }))
    setColumnsSetting(columnsSettingData)
    const actions = columnsData.filter((m) => m.dataIndex === 'action')
    setActionData(actions)
    // 需要配置字段的索引
    const visibleColumnsDataIndex = columns.map((m) => m.dataIndex as string)
    setVisibleColumnsDataIndex(visibleColumnsDataIndex)
  }, [t('activities:columns.activityTitle')])

  // 渲染展示的表头，根据dataIndex 选择的变化进行渲染
  // 操作列固定由 actionData 追加；若 visibleColumnsDataIndex 含 'action'，不能再从 columnsData 里选出一遍，否则会与 actionData 重复 key
  useEffect(() => {
    const showColumns = columnsData.filter(
      (item) =>
        item.dataIndex !== 'action' &&
        visibleColumnsDataIndex.includes(item.dataIndex as string),
    )
    setColumns([...showColumns, ...actionData])
  }, [visibleColumnsDataIndex, actionData])

  useEffect(() => {
    if (isUser) {
      setActivitySearchInfo({
        ...activitySearch,
        responsiblePersonId: undefined,
        ownerId: undefined,
        orgId: '',
        pageNum: 1,
      })
      setActivityFilterParams({
        responsiblePersonId: undefined,
        ownerId: undefined,
        orgId: '',
        pageNum: 1,
      })
      formRef.current.setFormItemValue('responsiblePersonId', undefined)
      formRef.current.setFormItemValue('ownerId', undefined)
      formRef.current.setFormItemValue('orgId', undefined)
    }
  }, [isUser])
  return (
    <div className='page-wrapper-box'>
      <PageWrapper
        headerTitle={
          <ViewSwitch
            title={t('activities:activities')}
            canAdminUserView={canAdminUserView}
            canHeadUserView={canHeadUserView}
            setIsUser={setIsUser}
            isUser={isUser}
          />
        }
      >
        <ListFilterForm
          ref={formRef}
          renderBtnJsx={
            <TopLeftBtn
              pageNum={1}
              pageSize={total}
              keyword={activitySearch.keyword}
              cycleId={activitySearch.cycleId}
              userView={isUser}
              orgId={activitySearch.orgId}
              responsiblePersonId={activitySearch.responsiblePersonId ?? ''}
              ownerId={activitySearch.ownerId ?? ''}
              startTime={activitySearch?.activitiesDate?.[0]}
              endTime={activitySearch?.activitiesDate?.[1]}
            />
          }
          showResetBtn={true}
          onReset={() => {
            formRef.current.resetForm()
            setActivitySearchInfo({
              ...activitySearchInitData,
            })
            setActivityFilterParams({
              ...activitySearchInitData,
            })
          }}
          // showKeywordInput
          onSubmit={(values) => {
            const searchCondition = {
              keyword: values.keyword,
              activitiesDate: values.activitiesDate,
              cycleId: values.cycleId,
              orgId: values.orgId,
              responsiblePersonId: values.responsiblePersonId,
              ownerId: values.ownerId,
              userView: isUser,
              pageNum: 1,
              pageSize: 20,
            }
            setActivitySearchInfo(searchCondition)
            setActivityFilterParams(searchCondition)
            tableRef.current?.refresh()
          }}
          renderSettingJsx={
            <PopSetting
              visibleColumns={columnsSetting}
              setVisibleColumnsDataIndex={setVisibleColumnsDataIndex}
              setPopVisible={setPopVisible}
              columnsFromServer={columnsFromServer}
              setColumnsFromServer={setColumnsFromServer}
              disableFiled={['initiativeName', 'name']}
              bizType={TableBizType.Activity}
            />
          }
          showSettingBtn={true}
          popVisible={popVisible}
          setPopVisible={setPopVisible}
        >
          <FormItem field={'activitiesDate'}>
            <RangePicker
              allowClear
              placeholder={[
                t('initiatives:initiativeInfo.initiativeStartDate'),
                t('initiatives:initiativeInfo.initiativeEndDate'),
              ]}
              style={{ width: 240 }}
              format='DD/MM/YYYY'
              onClear={() => {
                setActivitySearchInfo({
                  ...activitySearch,
                  activitiesDate: [],
                  pageNum: 1,
                })
                setActivityFilterParams({ activitiesDate: [], pageNum: 1 })
              }}
            />
          </FormItem>
          <FormItem field={'cycleId'}>
            <Select
              placeholder={t('activities:selectCycle')}
              style={{ width: 240 }}
              onChange={handleSelectChange}
            >
              {cycleList?.map((item: any, index: number) => {
                return (
                  <Select.Option key={index} value={item.value}>
                    {item.label}
                  </Select.Option>
                )
              })}
            </Select>
          </FormItem>

          {permissionJudgment('admin_or_initiativeAdmin_or_sector') &&
            !isUser && (
              <FormItem field={'responsiblePersonId'}>
                <Select
                  placeholder={t(
                    'project:projectActivityTablecolumns.responsiblePerson',
                  )}
                  options={initiativesOwnerData}
                  allowClear
                  showSearch
                  filterOption={(inputValue, option) =>
                    option.props.value
                      .toLowerCase()
                      .indexOf(inputValue.toLowerCase()) >= 0 ||
                    option.props.children
                      .toLowerCase()
                      .indexOf(inputValue.toLowerCase()) >= 0
                  }
                  style={{ width: 240 }}
                  onChange={(value) =>
                    initiativesResponsiblePersonChange(value)
                  }
                />
              </FormItem>
            )}

          {permissionJudgment('admin_or_initiativeAdmin_or_sector') &&
            !isUser && (
              <FormItem field={'ownerId'}>
                <Select
                  placeholder={t(
                    'initiatives:placeholders.enterInitiativeOwnerName',
                  )}
                  options={initiativesOwnerData}
                  allowClear
                  showSearch
                  filterOption={(inputValue, option) =>
                    option.props.value
                      .toLowerCase()
                      .indexOf(inputValue.toLowerCase()) >= 0 ||
                    option.props.children
                      .toLowerCase()
                      .indexOf(inputValue.toLowerCase()) >= 0
                  }
                  style={{ width: 240 }}
                  onChange={(value) => initiativesOwnerChange(value)}
                />
              </FormItem>
            )}

          {permissionJudgment('admin_or_initiativeAdmin') && !isUser && (
            <FormItem field={'orgId'}>
              <TreeSelect
                showSearch={true}
                placeholder={t('membersDepartments:columns.departmentName')}
                allowClear={true}
                treeData={departmentData}
                onChange={departmentNameChange}
                treeProps={{
                  onSelect: (v, n) => {
                    console.log(n)
                  },
                }}
                filterTreeNode={(inputText, node) => {
                  return (
                    node.props.title
                      .toLowerCase()
                      .indexOf(inputText.toLowerCase()) > -1
                  )
                }}
                style={{ width: 240 }}
              />
            </FormItem>
          )}
          <FormItem field={'keyword'} style={{ order: 5 }}>
            <Input.Search
              allowClear
              placeholder={t('common:searchPlaceholder')}
              style={{ width: 240 }}
            />
          </FormItem>
        </ListFilterForm>
        {!_.isEmpty(columns) && columns.length > 1 && (
          <UnifiedTableStyle
            rowKey={'activityId'}
            showNoColumn
            noColumnWidth={80}
            noColumnFixed='left'
            ref={tableRef}
            loading={true}
            columns={columns}
            getList={getList}
            onChange={tableChange}
          ></UnifiedTableStyle>
        )}
      </PageWrapper>
    </div>
  )
}

