// project 列表页面添加的按钮
type AddProjectBtnType = {
  pageNum: string | number
  pageSize: string | number
  startDate?: string
  endDate?: string
  projectManagerName?: string
  projectType?: string | number
  keyword?: string
  orgId?: string
  cycleId?: string | number
  userView?: boolean
  setOptionSelectVisible?: any
}
const AddProjectBtn = (props: AddProjectBtnType) => {
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['common', 'project', 'activities'])
  const navigate = useNavigate()
  const { pageSize: pageCount, setOptionSelectVisible } = props
  const checkPermission = useCheckPermission()
  const canProjectAdd = checkPermission(ProjectPermissionEnum.ADD)
  const ProjectsAdd = () => {
    navigate('/projects/projects-mgmt/edit/1')
  }
  const { run: exportProjectList, loading: exportProjectListLoading } =
    useRequest(exportProjectListRequest, {
      manual: true,
      onSuccess: (res: any) => {
        if (res) {
          const fileName = `${t('project:upperTitle')}-${dayjs().valueOf()}.xlsx`
          downloadFile(res.data, fileName)
        }
      },
    })
  return (
    <>
      {canProjectAdd && (
        <Button
          type='text'
          className={classNames('button-size-small')}
          icon={<IconPlus style={{ fill: '#fff' }} />}
          onClick={ProjectsAdd}
        >
          {t('common:btn.add')}
        </Button>
      )}
      <Button
        type='text'
        className={classNames(
          'button-size-small',
          'project-management-export-btn',
        )}
        icon={<IconExport style={{ transform: 'rotate(-90deg)' }} />}
        loading={exportProjectListLoading}
        disabled={+pageCount === 0 || exportProjectListLoading}
        onClick={() => {
          exportProjectList(props)
        }}
      >
        {t('common:btn.export')}
      </Button>
    </>
  )
}

const Projects = () => {
  const formRef = useRef(null)
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const [cylceList, setCylceList] = useState([])
  const [userList, setUserList] = useState([])
  const navigate = useNavigate()
  const location = useLocation()
  const { state } = location
  const tableRef = useRef(null)
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['project', 'common'])
  const checkPermission = useCheckPermission()
  const { projectSearch, setProjectSearchInfo } = useProjectInfo()
  const [filterParams, setFilterParams] =
    useSetState<ProjectFilterState>(ProjectFilterObject)
  const canProjectDelete = checkPermission(ProjectPermissionEnum.DELETE)
  const canEditForApprove = checkPermission(
    ProjectPermissionEnum.EditForApprove,
  )
  const canEdit = checkPermission(ProjectPermissionEnum.EDIT)
  const canPmEdit = checkPermission(ProjectPermissionEnum.PmEdit)
  const canAdminUserView = checkPermission(
    ProjectPermissionEnum.ProjectAdminUserView,
  )
  const headUserView = checkPermission(
    ProjectPermissionEnum.ProjectHeadUserView,
  )
  const canHeadUserView =
    canAdminUserView && headUserView ? false : headUserView

  const isSector = useIsSector()
  const isCreator = useIsCreator()

  const { isFromDashboard } = useParams()
  const {
    cycleId: dashBoardSelectedCycleId,
    startDate: dashBoardStartDate,
    endDate: dashBoardEndDate,
  } = useSelector<RootState, DashboardState>((state) => state.dashboard)

  const canProjectReview = checkPermission(ProjectPermissionEnum.REVIEW)
  const [viewEnum, setViewEnum] = useLocalStorageState<any>(
    viewEnumStorageKey,
    {
      defaultValue: ViewEnum.AdminView,
    },
  )
  const [optionSelectVisible, setOptionSelectVisible] = useState(false)
  const projectTypeOptions = [
    { label: t('project:projectType.strategic'), value: 0 },
    { label: t('project:projectType.operational'), value: 1 },
  ]

  const [selectCycleId, setSelectCycleId] = useState('id')
  const debouncedProjectDelete = useDebouncedPromise(projectDelete, 500)
  const { loading: deleteLoading, runAsync: runProjectDelete } = useRequest(
    debouncedProjectDelete,
    {
      manual: true,
      onSuccess: () => {
        Message.success(t('common:message.deleteSuccessfully'))
        const tableData = tableRef.current?.getData()
        const tableDataNo = tableData[0]['no']
        const deleteDataFlag = isInSequence(tableDataNo, tableData)
        if (deleteDataFlag && projectSearch.pageNum > 1) {
          const nowPage = Number(projectSearch.pageNum - 1)
          setProjectSearchInfo({ ...projectSearch, pageNum: nowPage })
          setFilterParams({ pageNum: nowPage })
        }
      },
    },
  )

  // 查询用户列表
  const { run: getAllUserList } = useRequest(getUserList, {
    manual: true,
    onSuccess(data: any, params) {
      const userOptions = data.map((item) => ({
        label: isLanguageAR
          ? `${item.fullNameAr}(${getMailString(item.mail)})`
          : `${item.fullName}(${getMailString(item.mail)})`,
        value: item.userId,
      }))
      setUserList(userOptions || [])
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })

  // 查询cycle列表
  const { run: getCylceByNowTime } = useRequest(getCylceByTime, {
    manual: true,
    onSuccess(data: any, params) {
      const cylceOptions = data.map((item) => ({
        label: isLanguageAR ? item.cycleNameAr : item.cycleName,
        value: item.id,
      }))
      setCylceList(cylceOptions || [])
      if (data.length) {
        const nowCycleId =
          isFromDashboard === undefined
            ? _.isEmpty(projectSearch.cycleId) || _.isEmpty(location.state)
              ? cylceOptions[0]?.value
              : projectSearch.cycleId
            : dashBoardSelectedCycleId
        formRef.current.setFormItemValue('cycleId', nowCycleId || '')
        setSelectCycleId(nowCycleId)
        if (isFromDashboard) {
          formRef.current.setFormItemValue('keyword', '')
          formRef.current.setFormItemValue('projectManagerName', undefined)
          formRef.current.setFormItemValue('orgId', undefined)
          const projectSelectData = [dashBoardStartDate, dashBoardEndDate]
          const projectTypeValue = location?.state?.projectType
          const dashboardType = location?.state?.dashboardType
          const projectType = ProjectType[projectTypeValue]
          formRef.current.setFormItemValue('projectType', projectType)
          if (dashboardType === DashboardTypeEnum.User) {
            setViewEnum(ViewEnum.UserView)
          } else if (dashboardType === DashboardTypeEnum.Admin) {
            setViewEnum(ViewEnum.AdminView)
          }
          setProjectSearchInfo({
            ...ProjectFilterObject,
            selectProjectDate: [...projectSelectData],
            cycleId: nowCycleId,
            projectType: projectType,
            keyword: '',
            orgId: '',
          })
          setFilterParams({
            selectProjectDate: projectSelectData,
            cycleId: nowCycleId,
            projectType: projectType,
            keyword: '',
            orgId: '',
          })
        } else {
          setProjectSearchInfo({ ...projectSearch })
          setFilterParams({ ...projectSearch })
        }
        // 如果点击左侧菜单，且不是从dashboard过来的，因为dashboard过来的state也是空的，所以要判断
        if (_.isEmpty(state) && isFromDashboard === undefined) {
          setProjectSearchInfo({
            ...ProjectFilterObject,
            cycleId: nowCycleId,
          })
          setFilterParams({
            ...ProjectFilterObject,
            cycleId: nowCycleId,
          })
          formRef.current.setFormItemValue('selectProjectDate', [])
          formRef.current.setFormItemValue('keyword', '')
          formRef.current.setFormItemValue('projectManagerName', undefined)
          formRef.current.setFormItemValue('orgId', undefined)
          formRef.current.setFormItemValue('projectType', undefined)
        }
        // 先有cycleId，根据cycleId查询对应的部门
        getOrgTree({ cycleId: nowCycleId })
      }
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })
  useEffect(() => {
    const projectSelectData =
      isFromDashboard === undefined
        ? _.isEmpty(projectSearch.selectProjectDate)
          ? []
          : [...projectSearch.selectProjectDate]
        : [dashBoardStartDate, dashBoardEndDate]
    formRef.current.setFormItemValue('selectProjectDate', projectSelectData)
    formRef.current.setFormItemValue('keyword', projectSearch.keyword || '')
    formRef.current.setFormItemValue(
      'projectManagerName',
      projectSearch.projectManagerName || undefined,
    )
    formRef.current.setFormItemValue('orgId', projectSearch.orgId || undefined)
    formRef.current.setFormItemValue(
      'projectType',
      projectSearch.projectType || undefined,
    )
    getCylceByNowTime()
    getAllUserList({ pageNum: 1, pageSize: 9999 })
    getProjectTableConfig(TableBizType.Project)
  }, [])
  const [totalNumber, setTotalNumber] = useState(0)
  const [deleteModalVisible, setDeleteModalVisible] = useState(false)
  const [projectId, setProjectId] = useState('')
  const [departmentData, setDepartmentData] = useState<any>([])

  const setDeleteVisible = (status: boolean, flag: string) => {
    setDeleteModalVisible(status)
    if (flag === 'ok') {
      runProjectDelete(projectId)
    } else {
      setProjectId('')
    }
  }

  const handelProjectDelete = (id) => {
    setDeleteModalVisible(true)
    setProjectId(id)
  }

  const handelProjectDetail = (id) => {
    navigate(`/projects/projects-mgmt/detail/4/${id}`)
  }
  const handelProjectGantt = (id) => {
    navigate(`/projects/milestones/ganttCharts/${id}`, {
      state: { locationFrom: 'productList' },
    })
  }

  //已经发布的项目可以进行编辑操作
  const handelPublishedProjectEdit = (id, workflowStatus, needApproval) => {
    // 如果需要审批，则跳转到审批页面
    if (needApproval) {
      navigate(`/projects/projects-mgmt/edit/4/${id}/1`)
    } else {
      // 如果审批流是未发布ubpublished，approve则跳转到编辑页面第一个页面，
      if (
        workflowStatus === WorkflowStatusEnum.Discarded ||
        workflowStatus === WorkflowStatusEnum.Approved
      ) {
        navigate(`/projects/projects-mgmt/edit/1/${id}/1`)
      } else {
        navigate(`/projects/projects-mgmt/edit/4/${id}/1`)
      }
    }
  }

const handelProjectEdit = (id, completionStatus) => {
    if (completionStatus === PROJECT_COMPLETION_STATUS.StepOne) {
      navigate(`/projects/projects-mgmt/edit/1/${id}`)
    }
    if (completionStatus === PROJECT_COMPLETION_STATUS.StepTwo) {
      navigate(`/projects/projects-mgmt/edit/2/${id}`)
    }
    if (
      completionStatus === PROJECT_COMPLETION_STATUS.StepThree ||
      completionStatus === PROJECT_COMPLETION_STATUS.StepFour
    ) {
      navigate(`/projects/projects-mgmt/edit/4/${id}`)
    }
  }



  const [reopenModalVisible, setReopenModalVisible] = useState(false)

  const debouncedProjectReopen = useDebouncedPromise(projectReopen, 500)
  const { loading: reopenLoading, runAsync: runProjectReopen } = useRequest(
    debouncedProjectReopen,
    {
      manual: true,
      onSuccess: () => {
        Message.success(t('common:message.reopenSuccessfully'))
        const tableData = tableRef.current?.getData()
        const tableDataNo = tableData[0]['no']
        const deleteDataFlag = isInSequence(tableDataNo, tableData)
        if (deleteDataFlag && projectSearch.pageNum > 1) {
          const nowPage = Number(projectSearch.pageNum - 1)
          setProjectSearchInfo({ ...projectSearch, pageNum: nowPage })
          setFilterParams({ pageNum: nowPage })
        }
      },
    },
  )

  const setReopenVisible = (status: boolean, flag: string) => {
    setReopenModalVisible(status)
    if (flag === 'ok') {
      runProjectReopen(projectId)
    } else {
      setProjectId('')
    }
  }

  const handelProjectReopen = (id) => {
    setReopenModalVisible(true)
    setProjectId(id)
  }

  const getProjectProgressColor = (isClose, value) => {
    if (isClose) {
      return '#d1d1d3'
    }
    return getProgressColor(value)
  }
  const getProgressDetailRate = (record) => {
    const progress = +record.completionOfDate
    const actualOfDate = +record.actualOfDate
    const targetOfDate = +record.targetOfDate
    return (
      <Popover
        content={
          <div style={{ display: 'flex', flexDirection: 'column' }}>
            <p style={{ display: 'inline-flex', gap: '10px' }}>
              <span>{t('activities:columns.avtual')}</span>:
              <span>{actualOfDate}</span>
            </p>
            <p style={{ display: 'inline-flex', gap: '10px' }}>
              <span>{t('activities:columns.target')}</span>:
              <span>{targetOfDate}</span>
