            style={{ cursor: 'pointer' }}
          >
            <Badge
              color={getDaysAgo(record.lastUpdateTime)}
              style={isLanguageAR ? { marginLeft: 6 } : { marginRight: 6 }}
            ></Badge>
            {renderEllipsisText(record.name, underline())}
          </div>
        )
      },
    },
    {
      title: t('project:projectTableColumns.completeRate'),
      dataIndex: 'completionOfDate',
      width: 250,
      render: (value, record) => {
        return getProgressDetailRate(record)
      },
    },
    {
      title: t('project:projectTableColumns.objectiveName'),
      dataIndex: 'objectiveName',
      width: 150,
      render: renderEllipsisText,
    },
    {
      title: t('project:projectTableColumns.projectManagerName'),
      dataIndex: 'projectManagerDetail',
      width: 160,
      render: (_, record) => {
        const projectManagerName = isLanguageAR
          ? record?.projectManagerDetail?.[0]?.nameAr
          : record?.projectManagerDetail?.[0]?.name
        return renderEllipsisText(projectManagerName)
      },
