    {
      title: t('project:projectInfo.projectProjectType'),
      dataIndex: 'projectType',
      width: 180,
      render: (_, record) => {
        const projectTypeName =
          record?.projectType === ProjectType.strategic
            ? t('project:projectType.strategic')
            : t('project:projectType.operational')
        return renderEllipsisText(projectTypeName)
      },
    },
    {
      title: t('project:projectDeleteInfo.teamMembers'),
      dataIndex: 'teamMembersDetail',
      width: 180,
      render: (_, record) => {
        return renderEllipsisText(record?.teamMembersDetail?.length)
      },
    },
    {
      title: t('project:projectDeleteInfo.dependents'),
      dataIndex: 'dependentsDetail',
      width: 180,
      render: (_, record) => {
        return renderEllipsisText(record?.dependentsDetail?.length)
      },
    },
    {
      title: t('project:projectTableColumns.startDate'),
      dataIndex: 'startDate',
      width: 150,
      render: renderEllipsisText,
    },
    {
      title: t('project:projectTableColumns.endDate'),
      dataIndex: 'endDate',
      width: 150,
      render: renderEllipsisText,
    },
    {
      title: t('project:projectTableColumns.budget'),
      dataIndex: 'budget',
      width: 130,
      render: (_, record) => {
        return renderEllipsisText(
          record.budget ? record.budget + ` AED` : 0 + ` AED`,
        )
      },
    },
    {
      title: t('budget:columns.actualBudget'),
      dataIndex: 'actualBudget',
      width: 131,
      render: (text, record) => {
        return renderEllipsisText(text ? text + ' AED' : 0 + ' AED')
      },
    },
    {
      title: t('budget:columns.expenses'),
      dataIndex: 'expense',
      width: 118,
      render: (text, record) => {
        return renderEllipsisText(text ? text + ' AED' : 0 + ' AED')
      },
    },
    {
      title: t('project:projectTableColumns.status'),
      dataIndex: 'status',
      width: 150,
      render: (value) => {
        return (
          <Badge
            color={STATUS_COLOR[value]}
            text={t(
              `project:projectReleaseStatus.${PROJECT_RELEASE_STATUS_TEXTS[value]}`,
            )}
          />
        )
      },
    },
    {
      title: t('project:projectTableColumns.workflowStatus'),
      dataIndex: 'workflowStatus',
      width: 150,
      render: (value) => {
        if (value === null || value === undefined) {
          return ''
        }
        return (
          <Badge
            color={Workflow_Status_Color[value]}
            text={t(`project:workflowStatus.${WorkflowStatusText[value]}`)}
