        )
      },
    },
    {
      title: t('common:columns.action'),
      fixed: 'right',
      dataIndex: 'action',
      width: 180,
      render: (_, record) => {
        const isPm = record?.viewEnum === ViewEnum.OwnerView
        return (
          <>
