                        icon={<IconEdit />}
                        className='coc-table-link'
                        onClick={() =>
                          handelPublishedProjectEdit(
                            record.id,
                            record.workflowStatus,
                            record.needApproval,
                          )
                        }
                      />
                    </Tooltip>,
                    record?.cycleStatus,
                  )}

                {record.status === ProjectReleaseStatusEnum.PUBLISHED &&
                  record.workflowStatus &&
                  (canProjectReview || canPmEdit) &&
                  !(
                    record.workflowStatus === WorkflowStatusEnum.Discarded ||
                    record.workflowStatus === WorkflowStatusEnum.Approved
                  ) &&
                  (!isAdmin && !isProjectAdmin && !isCreator ? isPm : true) &&
                  useConditionalButton(
                    <Tooltip content={t('common:btn.review')}>
                      <Link
                        icon={<IconCheckCircle />}
                        className='coc-table-link'
                        onClick={() =>
                          handelPublishedProjectEdit(
                            record.id,
                            record.workflowStatus,
                            record.needApproval,
                          )
                        }
                      />
                    </Tooltip>,
                    record?.cycleStatus,
                  )}
              </>
            )}

            {(isAdmin || isProjectAdmin) &&
              record.status === ProjectReleaseStatusEnum.CLOSED && (
                <Tooltip content={t('common:btn.open')}>
                  <Link
                    icon={<IconDriveFile />}
                    className='coc-table-link'
                    onClick={() => handelProjectReopen(record.id)}
                  />
                </Tooltip>
              )}
          </>
        )
      },
    },
  ]
  const [columns, setColumns] = useState([])
  //渲染checkbox组件的数据
  const [columnsSetting, setColumnsSetting] = useState([])
  const [visibleColumnsDataIndex, setVisibleColumnsDataIndex] = useState([])
  const [columnsFromServer, setColumnsFromServer] = useState([])
  const [actionData, setActionData] = useState([])
  const [popVisible, setPopVisible] = useState(false)

  const { run: getProjectTableConfig } = useRequest(getUserTableHeaderConfig, {
    manual: true,
    onSuccess(data: any, params) {
      const getColumnsFromServer = JSON.parse(data) ?? []
      if (!_.isEmpty(getColumnsFromServer)) {
        const columnServerData = columnsData.filter((item) =>
          getColumnsFromServer.includes(item.dataIndex as string),
        )
        setColumns(columnServerData)
        setVisibleColumnsDataIndex(getColumnsFromServer)
        setColumnsFromServer(getColumnsFromServer)
      } else {
        const visibleColumnsDataIndex = columnsData
          .filter((v) => v.dataIndex !== 'action')
          .map((m) => m.dataIndex as string)
        setTimeout(() => {
          setColumns(columnsData)
        }, 10)
        setColumnsFromServer(visibleColumnsDataIndex)
      }
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })
  useEffect(() => {
    // 需要配置的字段
    const columnsSettingData = columnsData
      .filter((m) => m.dataIndex !== 'action')
      .map((v) => ({ key: v.dataIndex as string, title: v.title }))
    setColumnsSetting(columnsSettingData)

    const actions = columnsData.filter((m) => m.dataIndex === 'action')
    setActionData(actions)
    // 需要配置字段的索引
    const visibleColumnsDataIndex = columns.map((m) => m.dataIndex as string)
    setVisibleColumnsDataIndex(visibleColumnsDataIndex)
  }, [t('project:projectTableColumns.name')])

  // 渲染展示的表头，根据dataIndex 选择的变化进行渲染
  // action 列单独放在 actionData 里追加；若 visible 里含 'action'，不能再从 columnsData 里筛出一遍，否则会与 actionData 重复、React key 重复
  useEffect(() => {
    const showColumns = columnsData.filter(
      (item) =>
        visibleColumnsDataIndex.includes(item.dataIndex as string) &&
        item.dataIndex !== 'action',
    )
    setColumns([...showColumns, ...actionData])
  }, [visibleColumnsDataIndex, actionData])

  const [tablePageParams, setTablePageParams] = useState({
    pageNum: 1,
    pageSize: 20,
  })
  //获取表格数据
  const getList = useCallback(
    (
      params: { pageNum: number; pageSize: number } = {
        pageNum: projectSearch.pageNum,
        pageSize: projectSearch.pageSize,
      },
    ) => {
      if (selectCycleId === 'id') {
        return Promise.resolve({
          list: [],
          total: 0,
          pageNum: projectSearch.pageNum,
          pageSize: projectSearch.pageSize,
        })
      }
      const allSearchFields = {
        keyword: projectSearch['keyword'],
        cycleId: projectSearch['cycleId'],
        projectManagerName: projectSearch['projectManagerName'],
        startDate: _.isEmpty(projectSearch['selectProjectDate'])
          ? ''
          : isFromDashboard === undefined
            ? projectSearch['selectProjectDate'][0]
            : projectSearch['selectProjectDate'][0] === dashBoardStartDate
              ? dashBoardStartDate
              : projectSearch['selectProjectDate'][0],
        endDate: _.isEmpty(projectSearch['selectProjectDate'])
          ? ''
          : isFromDashboard === undefined
            ? projectSearch['selectProjectDate'][1]
            : projectSearch['selectProjectDate'][1] === dashBoardEndDate
              ? dashBoardEndDate
              : projectSearch['selectProjectDate'][1],
        userView: viewEnum,
        orgId: projectSearch.orgId,
        projectType: projectSearch.projectType,
        ...params,
        pageNum: projectSearch.pageNum,
      }
      return projectList(allSearchFields).then((res: any) => {
        setTotalNumber(res?.total)
        const projectList = res?.list || []
        res.list = projectList.map((item) => {
          return {
            ...item,
            viewEnum: viewEnum,
            name: isLanguageAR ? item.nameAr : item.name,
            objectiveName: isLanguageAR
              ? item.objectiveNameAr
              : item.objectiveName,
          }
        })
        return {
          ...res,
          pageNum: allSearchFields.pageNum,
          pageSize: allSearchFields.pageSize,
        }
      })
    },
    [
      runProjectDelete,
      location,
      filterParams,
      deleteLoading,
      selectCycleId,
      runProjectReopen,
      reopenLoading,
    ],
  )

  useEffect(() => {
    setProjectSearchInfo({ ...projectSearch, userView: viewEnum })
    setFilterParams({ userView: viewEnum })
    tableRef.current?.refresh()
  }, [viewEnum])

  useEffect(() => {
    tableRef.current?.setPageNum(projectSearch.pageNum)
  }, [projectSearch])

  const tableChange = (pagination, sorter, filters) => {
    //export set pageNum to 1
    setTablePageParams({
      // pageNum: pagination.current,
      pageNum: 1,
      pageSize: pagination.pageSize,
    })
    setProjectSearchInfo({
      ...projectSearch,
      pageNum: pagination.current,
      pageSize: pagination.pageSize,
    })
    setFilterParams({ pageNum: pagination.current })
  }

  //获取department 列表
  const { run: getOrgTree } = useRequest(getOrgTreeRecursion, {
    manual: true,
    onSuccess(res: any, params) {
      formRef.current.setFormItemValue('orgId', undefined)
      const data = transformData(res, t)
      setDepartmentData(data || [])
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })

  const departmentNameChange = (value) => {
    setProjectSearchInfo({
      ...projectSearch,
      orgId: value,
      pageNum: 1,
    })
    setFilterParams({
      orgId: value,
      pageNum: 1,
    })
    tableRef.current?.refresh()
  }
  useEffect(() => {
    if (viewEnum == ViewEnum.OwnerView) {
      setProjectSearchInfo({
        ...projectSearch,
        projectManagerName: '',
        pageNum: 1,
      })
      setFilterParams({
        projectManagerName: '',
        pageNum: 1,
      })
      formRef.current.setFormItemValue('projectManagerName', undefined)
    } else if (viewEnum == ViewEnum.UserView) {
      setProjectSearchInfo({
        ...projectSearch,
        projectManagerName: '',
        orgId: '',
        pageNum: 1,
      })
      setFilterParams({
        projectManagerName: '',
        orgId: '',
        pageNum: 1,
      })
      formRef.current.setFormItemValue('projectManagerName', undefined)
      formRef.current.setFormItemValue('orgId', undefined)
    }
  }, [viewEnum])

  // handle cycle departMent search
  const handleCycleDepartSearch = (cycleId) => {
    getOrgTree({ cycleId })
  }
  return (
    <div className={'page-wrapper-box'}>
      <PageWrapper
        headerTitle={
          <ViewSwitch
            title={t('project:upperTitle')}
            canAdminUserView={canAdminUserView}
            canHeadUserView={canHeadUserView}
            type='project'
            viewEnum={viewEnum}
            setViewEnum={setViewEnum}
          />
        }
      >
        <ListFilterForm
          ref={formRef}
          showResetBtn={true}
          renderBtnJsx={
            <AddProjectBtn
              pageNum={tablePageParams.pageNum}
              pageSize={totalNumber}
              setOptionSelectVisible={setOptionSelectVisible}
              startDate={
                projectSearch['selectProjectDate']?.length
                  ? projectSearch['selectProjectDate'][0]
                  : undefined
              }
              endDate={
                projectSearch['selectProjectDate']?.length
                  ? projectSearch['selectProjectDate'][1]
                  : undefined
              }
              projectManagerName={projectSearch['projectManagerName']}
              projectType={projectSearch['projectType']}
              keyword={projectSearch['keyword']}
              orgId={projectSearch.orgId}
              cycleId={projectSearch.cycleId}
              userView={viewEnum}
            />
          }
          // showKeywordInput
          onSubmit={(values) => {
            setProjectSearchInfo({
              keyword: values.keyword,
              cycleId: values.cycleId || '',
              orgId: values?.orgId,
              projectType: values.projectType,
              projectManagerName: values.projectManagerName || '',
              selectProjectDate: values.selectProjectDate || [],
              userView: values.userView || false,
              pageNum: 1,
              pageSize: 20,
            })
            setFilterParams({
              keyword: values.keyword,
              cycleId: values.cycleId || '',
              orgId: values?.orgId,
              projectType: values?.projectType,
              projectManagerName: values.projectManagerName || '',
              selectProjectDate: values.selectProjectDate || [],
              userView: values.userView || false,
              pageNum: 1,
              pageSize: 20,
            })
            // search set pageNum to 1
            tableRef.current?.refresh()
          }}
          onReset={() => {
            formRef.current.resetForm()
            setProjectSearchInfo({
              ...ProjectFilterObject,
            })
            setFilterParams({
              ...ProjectFilterObject,
            })
          }}
          renderSettingJsx={
            <PopSetting
              visibleColumns={columnsSetting}
              setVisibleColumnsDataIndex={setVisibleColumnsDataIndex}
              setPopVisible={setPopVisible}
              columnsFromServer={columnsFromServer}
              setColumnsFromServer={setColumnsFromServer}
              disableFiled={['name']}
              bizType={TableBizType.Project}
            />
          }
          showSettingBtn={true}
          popVisible={popVisible}
          setPopVisible={setPopVisible}
        >
          <FormItem field={'selectProjectDate'}>
            <RangePicker
              allowClear
              placeholder={[t('project:startDate'), t('project:endDate')]}
              style={{ width: 240 }}
              format='DD/MM/YYYY'
              onClear={() => {
                setProjectSearchInfo({
                  ...projectSearch,
                  selectProjectDate: [],
                  pageNum: 1,
                })
                setFilterParams({ selectProjectDate: [], pageNum: 1 })
              }}
            />
          </FormItem>
          <FormItem field={'cycleId'}>
            <Select
              placeholder={t('project:placeholders.selectCycle')}
              style={{ width: 240 }}
              options={cylceList}
              onChange={(value) => {
                setProjectSearchInfo({
                  ...projectSearch,
                  cycleId: value,
                  orgId: '',
                  pageNum: 1,
                })
                setFilterParams({ cycleId: value, orgId: '', pageNum: 1 })
                handleCycleDepartSearch(value)
                tableRef.current?.refresh()
              }}
            />
          </FormItem>
          {permissionJudgment('admin_or_projectAdmin_or_sector') &&
            viewEnum != ViewEnum.UserView &&
            viewEnum != ViewEnum.OwnerView && (
              <FormItem field={'projectManagerName'}>
                <Select
                  placeholder={t(
                    'project:placeholders.enterProjectManagerName',
                  )}
                  options={userList}
                  allowClear
                  showSearch
                  filterOption={(inputValue, option) =>
                    option.props.value
                      .toLowerCase()
                      .indexOf(inputValue.toLowerCase()) >= 0 ||
                    option.props.children
                      .toLowerCase()
                      .indexOf(inputValue.toLowerCase()) >= 0
                  }
                  style={{ width: 240 }}
                  onChange={(value) => {
                    setProjectSearchInfo({
                      ...projectSearch,
                      projectManagerName: value,
                      pageNum: 1,
                    })
                    setFilterParams({
                      projectManagerName: value,
                      pageNum: 1,
                    })
                    tableRef.current?.refresh()
                  }}
                />
              </FormItem>
            )}
          {permissionJudgment('admin_or_projectAdmin') &&
            viewEnum != ViewEnum.UserView && (
              <FormItem field={'orgId'}>
                <TreeSelect
                  showSearch={true}
                  placeholder={t('membersDepartments:columns.departmentName')}
                  allowClear={true}
                  treeData={departmentData}
                  onChange={departmentNameChange}
                  treeProps={{
                    onSelect: (v, n) => {
                      console.log(n)
                    },
                  }}
                  filterTreeNode={(inputText, node) => {
                    return (
                      node.props.title
                        .toLowerCase()
                        .indexOf(inputText.toLowerCase()) > -1
                    )
                  }}
                  style={{ width: 240 }}
                />
              </FormItem>
            )}

          <FormItem field={'projectType'}>
            <Select
              placeholder={t('project:projectInfo.projectProjectType')}
              options={projectTypeOptions}
              allowClear
              filterOption={(inputValue, option) =>
                option.props.value
                  .toLowerCase()
                  .indexOf(inputValue.toLowerCase()) >= 0 ||
                option.props.children
                  .toLowerCase()
                  .indexOf(inputValue.toLowerCase()) >= 0
              }
              style={{ width: 240 }}
              onChange={(value) => {
                setProjectSearchInfo({
                  ...projectSearch,
                  projectType: value,
                  pageNum: 1,
                })
                setFilterParams({
                  projectType: value,
                  pageNum: 1,
                })
                tableRef.current?.refresh()
              }}
            />
          </FormItem>

          <FormItem field={'keyword'}>
            <Input.Search
              allowClear
              placeholder={t('common:searchPlaceholder')}
              style={{ width: 240 }}
            />
          </FormItem>
        </ListFilterForm>
        {!_.isEmpty(columns) && columns.length > 1 && (
          <UnifiedTableStyle
            rowKey={'id'}
            showNoColumn
            noColumnWidth={80}
            noColumnFixed='left'
            loading={true}
            ref={tableRef}
            columns={columns}
            getList={getList}
            onChange={tableChange}
          ></UnifiedTableStyle>
        )}

        <ProjectDeleteModal
          deleteModalVisible={deleteModalVisible}
          setDeleteVisible={setDeleteVisible}
        />
        <ModalWindowFooter
          title={t('common:confirmation')}
          visible={reopenModalVisible}
          setVisible={(status, flag) => setReopenVisible(status, flag)}
          tipText={t('project:projectReopenModal.tipText')}
          cancelText={t('common:btn.cancel')}
          okText={t('common:btn.ok')}
        />
      </PageWrapper>
    </div>
  )
}

