  const uploadCustomRequest = async (option) => {
    setIsUploading(true)
    const { file } = option
    setUploadList(uploadList.concat([{ file, percent: 0, finish: false }]))
    const config = {
      onUploadProgress: (progressEvent) => {
        if (progressEvent.lengthComputable) {
          const percentCompleted = Math.round(
            (progressEvent.loaded * 100) / progressEvent.total,
          )
          updateProgress(file, percentCompleted)
        }
      },
      cancelToken: new CancelToken((cancel) => {
        cancelUpload = cancel
      }),
    }
    const type = File_UPLOAD_TYPE.KPI_IMPORT
    const uniqueId = UniqueId()
    const uid = Number(
      `${Date.now()}${Math.floor(Math.random() * 90000) + 10000}`,
    )
    const formData: any = new FormData()
    formData.append('file', file)
    formData.append('type', type)
    formData.append('uniqueId', uniqueId)
    formData.append('uid', uid)
    uploadFile(formData, config)
