                  return (
                    node.props.title
                      .toLowerCase()
                      .indexOf(inputText.toLowerCase()) > -1
                  )
                }}
                style={{ width: 240 }}
              />
            </FormItem>
          )}

          <FormItem field={'type'} style={{ order: 8 }}>
