          title={t('common:upload')}
          visible={
            importTemplateType === kpiImportTypeEnum.QuarterlyImport
              ? uploadExcelVisible
              : uploadMonthlyExcelVisible
          }
          style={{ width: 640 }}
          autoFocus={false}
          focusLock={true}
