              <Button
                loading={importLoading}
                onClick={() => {
                  handleUploadCancel(importTemplateType)
                }}
              >
                {t('common:btn.cancel')}
              </Button>
              <Button
                loading={importLoading}
                onClick={() => {
                  handleImportExcel(importTemplateType)
                }}
                type='primary'
              >
                {t('common:btn.import')}
              </Button>
            </>
          }
        >
          <div className='upload-excel-form'>
            <Form form={formMilestone} layout='vertical'>
              <Row gutter={40}>
                <Col span={24}>
                  <div className='upload-tips'>
                    {t('kpis:uploadTip')}
                    <Popover
                      trigger='hover'
                      position='top'
                      content={uploadTipsDom()}
                      className={'info-icon-tips'}
                    >
                      <IconInfoCircle />
                    </Popover>
                  </div>
                  <FormItem
                    field={`uploadMilestoneExcel`}
                    rules={[
                      {
                        required: true,
                        message: t('project:uploadExcelForm.ruleCheckMsg'),
                      },
                      {
                        validator(value, cb) {
                          if (_.isEmpty(fileList)) {
                            return cb(t('project:aedMaximumTip'))
                          }
                          return cb()
                        },
                      },
                    ]}
                  >
                    <div
                      className='download-kpi-template'
                      onClick={() => handlePreview(importTemplateType)}
                    >
                      <IconFile />
                      <span className='action-name'>
                        {t('indexKpi:indexKpiTemplate')}
                      </span>
                    </div>

                    <Upload
                      drag
                      accept='.xlsx'
                      multiple={false}
                      name='files'
                      showUploadList={false}
                      disabled={fileList.length > 0 || uploadList.length > 0}
                      // customRequest={handleFileChange}
                      onDrop={(e) => {
                        let uploadFile = e.dataTransfer.files[0]
                        if (isAcceptFile(uploadFile, 'xlsx')) {
                          return
                        } else {
                          Message.error(
                            t('project:uploadExcelForm.fileTypeCheckMsg'),
                          )
                        }
                      }}
                      tip={t('project:uploadExcelForm.fileTypeCheckMsg')}
                      customRequest={(option) => {
                        return uploadCustomRequest(option)
                      }}
                    >
                      <>
                        {fileList.map((attach, aindex) => {
                          return (
                            <div key={attach.url}>
                              <div className='drag-box drag-box-text-left'>
                                <FileIcon attach={attach} />
                                <span className='drag-area-title'>
                                  {attach.fileName}
                                </span>
                                <IconCloseCircle
                                  className='close-icon'
                                  onClick={(e) => {
                                    e.stopPropagation()
                                    handleUploadExcelDelete(attach.id)
                                  }}
                                />
                              </div>
                            </div>
                          )
                        })}
                        {fileList.length === 0 && !isUploading && (
                          <>
                            <div
                              className={classNames({
                                [`drag-box`]: true,
                                [`red-color`]: changeBorderColor,
                              })}
                            >
                              <IconUpload style={{ color: '#30647f' }} />
                              <span className='drag-area-title'>
                                {t('project:uploadExcelForm.formUploadTip')}
                              </span>
                            </div>
                          </>
                        )}
                        {isUploading &&
                          uploadList.map((file, index) => {
                            return (
                              <div key={`${index}-index`}>
                                <div className='drag-box'>
                                  {!file.finish && (
                                    <IconLoading className='loading-icon' />
                                  )}
                                </div>
                              </div>
                            )
                          })}
                      </>
                    </Upload>
                    {/* 错误table数据 */}
                    {!_.isEmpty(uploadFileErrorData) && (
                      <Table
                        // key={'rowNum'}
                        rowKey={(record) => `row-${record.rowNum}`}
                        className='error-table'
                        columns={uploadFileErrorColumns}
                        data={uploadFileErrorData}
                        scroll={{ x: true }}
                        pagination={false}
                        rowClassName={() => {
                          return 'error-table-row'
                        }}
                      />
                    )}
                  </FormItem>
                </Col>
              </Row>
            </Form>
          </div>
        </Modal>
      </PageWrapper>
    </div>
  )
}

