            <ExpensesTables
              ref={expensesRef}
              data={expensesActivityList}
              readOnly={readOnly}
            />
          )}
        </>
      ),
    },
  ]
  const getDetailById = (id, isUserView) => {
    const completionRateRequest = { milestoneId: id, userView: isUserView }
    setActivityLoading(true)
    setExpensesLoading(true)
    getMilestoneCompletionRateDetailById(completionRateRequest)
      .then((res: any) => {
        setMilestoneDetailData(res)
        const milestoneActivityListData = res?.activityList || []
        const milestonesName = isLanguageAR
          ? res?.milestoneNameAr
          : res?.milestoneName
        const endDate = res?.endDate
        setPageHeaderTitle(milestonesName)
