            const filteredPersonCompletionRates = (
              item.personCompletionRates || []
            )
              .map((value) => {
                const rates = (value?.completionRates || []).filter(
                  (v) => Number(v?.target ?? 0) !== 0,
                )
                return { ...value, completionRates: rates }
              })
              .filter((value) => (value?.completionRates || []).length > 0)

