          projectNameAr={milestoneDetailData['milestoneNameAr']}
          sendUserId={milestoneDetailData['projectManagerId']}
          sendUserName={null}
          sendUserNameAr={null}
          type='milestone'
          hint={hint}
          // extInfo={extInfo}
        />
      )}
    </div>
  )
}

