type ExportParamsType = {
  pageNum: number | string
  pageSize: number | string
  cycleId?: string | number
  projectId?: string | number
  orgId?: string | number
  pmId?: string | number
  keyword?: string
  userView?: boolean
}
type TopLeftBtnProps = {
  isList: boolean
  exportParams: ExportParamsType
}
const TopLeftBtn = (props: TopLeftBtnProps) => {
  const { isList, exportParams } = props
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['common', 'cycle', 'milestones', 'activities'])
  const navigate = useNavigate()
  const { run: exportMilestone, loading: exportLoading } = useRequest(
    exportMilestoneRequest,
    {
      manual: true,
      onSuccess: (res: any) => {
        if (res) {
          let fileName = `${t('milestones:milestones')}-${dayjs().valueOf()}.xlsx`
          downloadFile(res.data, fileName)
        }
      },
    },
  )
  return (
    <div>
      <Link
        icon={<ViewChartIcon />}
        className='coc-table-link'
        onClick={() => {
          navigate('/projects/milestones/ganttCharts')
        }}
      >
        {t('milestones:viewGanttChart')}
      </Link>
      <span style={{ margin: '0 10px', color: '#E5E6EB' }}>|</span>
      <Link
        icon={
          exportLoading ? (
            <IconLoading />
          ) : (
            <IconExport className='rotate-icon' />
          )
        }
        className='coc-table-link'
        onClick={() => exportMilestone(exportParams)}
        disabled={exportLoading || isList}
      >
        {t('common:btn.export')}
      </Link>
    </div>
  )
}

const getProgressColor = (value) => {
  if (value <= 70) return '#F5626C'
  if (value <= 89) return '#F78956'
  return '#45AD5E'
}
const Milestones = () => {
  const navigate = useNavigate()
  const listFilterRef = useRef(null)
  const lang = useLanguage()
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['common', 'cycle', 'milestones', 'project'])
  const tableRef = useRef(null)
  const [totalNumber, setTotalNumber] = useState(0)
  const { milestoneSearch, setMilestoneSearchInfo } = useMilestone()
  const [milestoneParams, setMilestoneParams] =
    useSetState<milestoneSearchState>(milestoneSearchInitData)
  const location = useLocation()
  const { state } = location
  const { cycleId } = state || {}
  const { projectId: viewMoreProjectId } = useParams()
  const [milesProjects, setMilesProjects] = useState([])
  const [cycleOptions, setCycleOptions] = useState([])
  const [selectCycleId, setSelectCycleId] = useState('id')
  const [isList, setIsList] = useState(false)
  const [publishedAndCloseProjects, setPublishedAndCloseProjects] = useState([])
  const checkPermission = useCheckPermission()
  const canAdminUserView = checkPermission(
    ProjectPermissionEnum.MilestoneAdminUserView,
  )
  const headUserView = checkPermission(
    ProjectPermissionEnum.MilestoneHeadUserView,
  )
  const canHeadUserView =
    canAdminUserView && headUserView ? false : headUserView

  const [viewEnum, setViewEnum] = useLocalStorageState<any>(
    viewEnumStorageKey,
    {
      defaultValue: ViewEnum.AdminView,
    },
  )
  const isAdmin = useIsAdmin()
  const isProjectAdmin = useIsProjectAdmin()

  //下拉框数据
  const [departmentData, setDepartmentData] = useState<any>([])
  const [ownerData, setOwnerData] = useState<any>([])

  //判断是否使用路由传递过来的 projectId
  const [enableViewMore, setEnableViewMore] = useState(true)

  //获取表格数据
  const getList = useCallback(
    (
      page: { pageNum: number; pageSize: number } = {
        pageNum: milestoneSearch.pageNum,
        pageSize: milestoneSearch.pageSize,
      },
    ) => {
      if (selectCycleId === 'id') {
        return Promise.resolve({ list: [], total: 0 })
      }
      return new Promise((resolve, reject) => {
        getMilestoneList({
          cycleId: milestoneSearch.cycleId,
          keyword: milestoneSearch?.keyword,
          projectId:
            enableViewMore && viewMoreProjectId
              ? viewMoreProjectId
              : milestoneSearch?.projectId,
          userView: viewEnum,
          ...page,
          orgId: milestoneSearch?.orgId,
          pmId: milestoneSearch?.pmId,
          pageNum: milestoneSearch.pageNum,
        })
          .then((res: any) => {
            if (res?.list.length > 0) {
              let projectList = []
              let tempList = res.list.map((item, index) => {
                projectList.push(
                  lang === LanguageEnum.EN
                    ? item.projectName
                    : item.projectNameAr,
                )
                return {
                  id: item.id,
                  name: item.name,
                  projects:
                    lang === LanguageEnum.EN
                      ? item.projectName
                      : item.projectNameAr,
                  startDate: item.startDate,
                  endDate: item.endDate,
                  budget: item.budget,
                  expenses: item.expenses,
                  milestoneCompletionRate: item.completionOfDate,
                  releaseStatus: item.status,
                  workflowStatus: item.workflowStatus,
                  projectId: item.projectId,
                  actualOfDate: item.actualOfDate,
                  targetOfDate: item.targetOfDate,
                  cycleStatus: item.cycleStatus,
                }
              })
              setMilesProjects(_.uniq(projectList))
              setIsList(false)
              setTotalNumber(res.total)
              resolve({
                total: res.total,
                list: tempList,
                pageNum: milestoneSearch.pageNum,
                pageSize: milestoneSearch.pageSize,
              })
            } else {
              setIsList(true)
              resolve({
                total: 0,
                list: [],
                pageNum: milestoneSearch.pageNum,
                pageSize: milestoneSearch.pageSize,
              })
            }
          })
          .catch((err) => {
            resolve([])
          })
      })
    },
    [location, milestoneParams],
  )

  const { run: runGetPublishAndCloseProject } = useRequest(
    getPublishAndCloseProject,
    {
      manual: true,
      onSuccess: (res: any) => {
        if (res) {
          const projectOptions = res.map((item) => ({
            label: lang === LanguageEnum.EN ? item.name : item.nameAr,
            value: item.projectId,
          }))
          setPublishedAndCloseProjects(projectOptions || [])
        }
      },
    },
  )
  //获取department 列表
  const { run: getOrgTree } = useRequest(getOrgTreeRecursion, {
    manual: true,
    onSuccess(res: any, params) {
      listFilterRef?.current?.setFormItemValue('orgId', undefined)
      const data = transformData(res, t)
      setDepartmentData(data || [])
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })
  const { run: getAllUserList } = useRequest(getUserList, {
    manual: true,
    onSuccess(data: any, params) {
      const userOptions = data.map((item) => ({
        label: isLanguageAR
          ? `${item.fullNameAr}(${getMailString(item.mail)})`
          : `${item.fullName}(${getMailString(item.mail)})`,
        value: item.userId,
      }))
      setOwnerData(userOptions || [])
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })

  //获取cycle name and id list
  const getCycleOptions = () => {
    getCycleIdAndName().then((res: any) => {
      if (res?.length > 0) {
        let temp = res.map((item) => ({
          label: lang == LanguageEnum.EN ? item.cycleName : item.cycleNameAr,
          value: item.id,
        }))
        setCycleOptions(temp)
        const nowCycleId = cycleId
          ? cycleId
          : _.isEmpty(milestoneSearch.cycleId) || _.isEmpty(location.state)
            ? temp[0]?.value || ''
            : milestoneSearch.cycleId
        listFilterRef?.current?.setFormItemValue('cycleId', nowCycleId)

        setMilestoneSearchInfo({
          ...milestoneSearch,
          cycleId: nowCycleId,
        })
        setMilestoneParams({ cycleId: nowCycleId })
        // 点击左侧菜单
        if (_.isEmpty(state)) {
          setMilestoneSearchInfo({
            ...milestoneSearchInitData,
            cycleId: nowCycleId,
          })
          setMilestoneParams({
            ...milestoneSearchInitData,
            cycleId: nowCycleId,
          })
          setTimeout(() => {
            listFilterRef?.current?.setFormItemValue('keyword', '')
            listFilterRef?.current?.setFormItemValue('projectId', undefined)
            listFilterRef?.current?.setFormItemValue('pmId', undefined)
            listFilterRef?.current?.setFormItemValue('orgId', undefined)
          }, 10)
        }
        // 从产品详情页过来
        if (!_.isEmpty(viewMoreProjectId)) {
          setMilestoneSearchInfo({
            ...milestoneSearchInitData,
            cycleId: nowCycleId,
            projectId: viewMoreProjectId,
            keyword: '',
            orgId: '',
            pmId: '',
          })
          setMilestoneParams({
            ...milestoneSearchInitData,
            cycleId: nowCycleId,
            projectId: viewMoreProjectId,
            keyword: '',
            orgId: '',
            pmId: '',
          })
          listFilterRef?.current?.setFormItemValue('keyword', '')
          listFilterRef?.current?.setFormItemValue('pmId', undefined)
          listFilterRef?.current?.setFormItemValue('orgId', undefined)
        } else {
          listFilterRef?.current?.setFormItemValue(
            'keyword',
            milestoneSearch.keyword,
          )
        }
        setSelectCycleId(nowCycleId)
        runGetPublishAndCloseProject({
          cycleId: nowCycleId,
        })
        getOrgTree({ cycleId: nowCycleId })
      }
    })
  }

  //table change 回调
  const tableChange = (pagination, sorter, filters) => {
    setMilestoneSearchInfo({
      ...milestoneSearch,
      pageNum: pagination.current,
    })
    setMilestoneParams({ pageNum: pagination.current })
  }

  // 讲数据转为千分位展示
  const formatNumberWithCommas = (number) => {
    // 将数字转换为字符串
    let numStr = number.toString()
    // 检查是否为负数，如果是，则将负号单独处理
    let isNegative = numStr.startsWith('-')
    if (isNegative) {
      numStr = numStr.slice(1)
    }
    // 使用正则表达式将每三个字符插入一个逗号
    let formattedStr = numStr.replace(/\B(?=(\d{3})+(?!\d))/g, ',')
    // 如果原数字是负数，则将负号加回
    if (isNegative) {
      formattedStr = '-' + formattedStr
    }
    return formattedStr
  }
  const handelmilestonesCompletionRate = (milestoneId, releaseStatus) => {
    navigate(`/projects/milestones/completionRate/${milestoneId}`, {
      state: { releaseStatus },
    })
  }

  const getProgressDetailRate = (record) => {
    const progress = +record.milestoneCompletionRate
    const actualOfDate = +record.actualOfDate
    const targetOfDate = +record.targetOfDate
    return (
      <Popover
        content={
          <div style={{ display: 'flex', flexDirection: 'column' }}>
            <p style={{ display: 'inline-flex', gap: '10px' }}>
              <span>{t('activities:columns.avtual')}</span>:
              <span>{actualOfDate}</span>
            </p>
            <p style={{ display: 'inline-flex', gap: '10px' }}>
              <span>{t('activities:columns.target')}</span>:
              <span>{targetOfDate}</span>
            </p>
          </div>
        }
      >
        <Progress
          percent={roundDown(progress)}
          color={getProgressColor(progress)}
        />
      </Popover>
    )
  }

  const columnsData: TableColumnProps[] = [
    {
      title: t('milestones:list.column.name'),
      dataIndex: 'name',
      width: 170,
      render: renderEllipsisText,
    },
    {
      title: t('milestones:list.column.rate'),
      dataIndex: 'milestoneCompletionRate',
      width: 200,
      render: (value, record) => {
        return getProgressDetailRate(record)
      },
    },
    {
      title: t('milestones:list.column.projects'),
      dataIndex: 'projects',
      width: 180,
      render: (_, record) => {
        return (
          <div
            onClick={() =>
              jumpToDetailsPage({
                type: 'milestones',
                id: record.projectId,
                navigate,
              })
            }
            style={{ cursor: 'pointer' }}
          >
            {renderEllipsisText(record.projects, underline())}
          </div>
        )
      },
    },

    {
      title: t('milestones:list.column.startDate'),
      dataIndex: 'startDate',
      width: 150,
      render: renderEllipsisText,
    },
    {
      title: t('milestones:list.column.endDate'),
      dataIndex: 'endDate',
      width: 150,
      render: renderEllipsisText,
    },
    {
      title: t('milestones:list.column.budget'),
      dataIndex: 'budget',
      width: 150,
      render: (value, record) => {
        return renderEllipsisText(
          record?.budget ? formatNumberWithCommas(record?.budget) : 0,
        )
      },
    },
    {
      title: t('milestones:list.column.expenses'),
      dataIndex: 'expenses',
      width: 150,
      render: (value, record) => {
        return renderEllipsisText(
          record.expenses ? formatNumberWithCommas(record.expenses) : '',
        )
      },
    },

    {
      title: t('milestones:list.column.status'),
      dataIndex: 'releaseStatus',
      width: 180,
      render: (value) => {
        return (
          <Badge
            color={STATUS_COLOR[value]}
            text={t(
              `project:projectReleaseStatus.${PROJECT_RELEASE_STATUS_TEXTS[value]}`,
            )}
          />
        )
      },
      // filteredValue: statusFilteredValue,
      // filters: [
      //   {
      //     text: t('project:projectReleaseStatus.draft'),
      //     value: ProjectReleaseStatusEnum.Draft,
      //   },
      //   {
      //     text: t('project:projectReleaseStatus.published'),
      //     value: ProjectReleaseStatusEnum.PUBLISHED,
      //   },
      //   {
      //     text: t('project:projectReleaseStatus.closed'),
      //     value: ProjectReleaseStatusEnum.CLOSED,
      //   },
      // ],
      // defaultFilters: [],
      // onFilter: (value, row) => {
      //   return row.releaseStatus == value
      // },
    },
    {
      title: t('milestones:list.column.workflowStatus'),
      dataIndex: 'workflowStatus',
      width: 150,
      render: (value) => {
        if (value === null || value === undefined) {
          return ''
        }
        return (
          <Badge
            color={Workflow_Status_Color[value]}
            text={t(`project:workflowStatus.${WorkflowStatusText[value]}`)}
          />
        )
      },
    },
    {
      title: t('milestones:list.column.action'),
      dataIndex: 'action',
      width: 80,
      fixed: 'right',
      render: (_, record) => {
        if (
          record.releaseStatus == ProjectReleaseStatusEnum.PUBLISHED &&
          !(
            record.workflowStatus === WorkflowStatusEnum.Rejected ||
            record.workflowStatus === WorkflowStatusEnum.PendingApproval
          )
        ) {
          return useConditionalButton(
            <Tooltip content={t('milestones:completionRate')}>
              <Link
                icon={<IconUpload />}
                className='coc-table-link'
                onClick={() =>
                  handelmilestonesCompletionRate(
                    record.id,
                    record.releaseStatus,
                  )
                }
              />
            </Tooltip>,
            record?.cycleStatus,
          )
        } else if (
          record.releaseStatus == ProjectReleaseStatusEnum.CLOSED &&
          (isAdmin || isProjectAdmin)
        ) {
          return (
            <Tooltip content={t('common:btn.detail')}>
              <Link
                icon={<IconEye />}
                className='coc-table-link'
                onClick={() =>
                  handelmilestonesCompletionRate(
                    record.id,
                    record.releaseStatus,
                  )
                }
              />
            </Tooltip>
          )
        }
      },
    },
  ]
  useEffect(() => {
    listFilterRef?.current?.setFormItemValue(
      'projectId',
      milestoneSearch.projectId || viewMoreProjectId,
    )
    listFilterRef?.current?.setFormItemValue(
      'pmId',
      milestoneSearch.pmId || undefined,
    )
    listFilterRef?.current?.setFormItemValue(
      'orgId',
      milestoneSearch.orgId || undefined,
    )
    // setProjectFilteredValue(undefined)
    // setStatusFilteredValue(undefined)
    getCycleOptions()
    getProjectTableConfig(TableBizType.Milestone)
  }, [lang])

  useEffect(() => {
    setMilestoneSearchInfo({
      ...milestoneSearch,
      userView: viewEnum,
    })

    setMilestoneParams({
      userView: viewEnum,
    })
    tableRef.current?.refresh()
  }, [viewEnum])

  useEffect(() => {
    // tableRef.current.refresh()
    tableRef.current?.setPageNum(milestoneSearch.pageNum)
  }, [milestoneParams])

  const handelChangeCycle = (value) => {
    setMilestoneSearchInfo({
      ...milestoneSearch,
      cycleId: value,
      orgId: '',
      pageNum: 1,
    })
    setMilestoneParams({ cycleId: value, orgId: '', pageNum: 1 })
    runGetPublishAndCloseProject({ cycleId: value })
    getOrgTree({ cycleId: value })
  }
  useEffect(() => {
    getAllUserList({ pageNum: 1, pageSize: 9999 })
  }, [])

  const departmentNameChange = (value) => {
    setMilestoneSearchInfo({
      ...milestoneSearch,
      orgId: value,
      pageNum: 1,
    })
    setMilestoneParams({
      orgId: value,
      pageNum: 1,
    })
    tableRef.current?.refresh()
  }
  const ownerChange = (value) => {
    setMilestoneSearchInfo({
      ...milestoneSearch,
      pmId: value,
      pageNum: 1,
    })
    setMilestoneParams({
      pmId: value,
      pageNum: 1,
    })
    tableRef.current?.refresh()
  }

  const [columns, setColumns] = useState([])
  //渲染checkbox组件的数据
  const [columnsSetting, setColumnsSetting] = useState([])
  const [visibleColumnsDataIndex, setVisibleColumnsDataIndex] = useState([])
  const [columnsFromServer, setColumnsFromServer] = useState([])
  const [actionData, setActionData] = useState([])
  const [popVisible, setPopVisible] = useState(false)

  const { run: getProjectTableConfig } = useRequest(getUserTableHeaderConfig, {
    manual: true,
    onSuccess(data: any, params) {
      const getColumnsFromServer = JSON.parse(data) ?? []
      if (!_.isEmpty(getColumnsFromServer)) {
        const columnServerData = columnsData.filter((item) =>
          getColumnsFromServer.includes(item.dataIndex as string),
        )
        setColumnsFromServer(getColumnsFromServer)
        setColumns(columnServerData)
        setVisibleColumnsDataIndex(getColumnsFromServer)
      } else {
        const visibleColumnsDataIndex = columnsData
          .filter((v) => v.dataIndex !== 'action')
          .map((m) => m.dataIndex as string)
        // 解决表头异步加载不出来的问题
        setTimeout(() => {
          setColumns(columnsData)
        }, 10)
        setColumnsFromServer(visibleColumnsDataIndex)
      }
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })
  useEffect(() => {
    // 需要配置的字段
    const columnsSettingData = columnsData
      .filter((m) => m.dataIndex !== 'action')
      .map((v) => ({ key: v.dataIndex as string, title: v.title }))
    setColumnsSetting(columnsSettingData)
    const actions = columnsData.filter((m) => m.dataIndex === 'action')
    setActionData(actions)
    // 需要配置字段的索引
    const visibleColumnsDataIndex = columns.map((m) => m.dataIndex as string)
    setVisibleColumnsDataIndex(visibleColumnsDataIndex)
  }, [t('milestones:list.column.name')])

  // 渲染展示的表头，根据dataIndex 选择的变化进行渲染
  useEffect(() => {
    const showColumns = columnsData.filter((item) =>
      visibleColumnsDataIndex.includes(item.dataIndex as string),
    )
    setColumns([...showColumns, ...actionData])
  }, [visibleColumnsDataIndex])

  useEffect(() => {
    if (viewEnum == ViewEnum.OwnerView) {
      setMilestoneSearchInfo({
        ...milestoneSearch,
        pmId: '',
        pageNum: 1,
      })
      setMilestoneParams({
        pmId: '',
        pageNum: 1,
      })
      listFilterRef?.current?.setFormItemValue('pmId', undefined)
    } else if (viewEnum == ViewEnum.UserView) {
      setMilestoneSearchInfo({
        ...milestoneSearch,
        pmId: '',
        orgId: '',
        pageNum: 1,
      })
      setMilestoneParams({
        pmId: '',
        orgId: '',
        pageNum: 1,
      })
      listFilterRef?.current?.setFormItemValue('pmId', undefined)
      listFilterRef?.current?.setFormItemValue('orgId', undefined)
    }
  }, [viewEnum])

  return (
    <div className={'page-wrapper-box'}>
      <PageWrapper
        headerTitle={
          <ViewSwitch
            title={t('milestones:milestonesManagement.title')}
            canAdminUserView={canAdminUserView}
            canHeadUserView={canHeadUserView}
            type='project'
            viewEnum={viewEnum}
            setViewEnum={setViewEnum}
          />
        }
      >
        <div className='search-container'>
          <ListFilterForm
            ref={listFilterRef}
            showResetBtn={true}
            renderBtnJsx={
              <TopLeftBtn
                isList={isList}
                exportParams={{
                  projectId: milestoneSearch.projectId,
                  keyword: milestoneSearch.keyword,
                  pageNum: 1,
                  pageSize: totalNumber,
                  cycleId: milestoneSearch.cycleId,
                  userView: viewEnum,
                  orgId: milestoneSearch.orgId,
                  pmId: milestoneSearch.pmId,
                }}
              />
            }
            // showKeywordInput
            // onFilterParamsChange={setFilterParams}
            onSubmit={(values) => {
              const searchCondition = {
                cycleId: values.cycleId,
                userView: viewEnum,
                projectId: values?.projectId,
                orgId: values?.orgId,
                pmId: values?.pmId,
                keyword: values?.keyword,
                pageNum: 1,
                pageSize: 20,
