              )}
            <FormItem field={'keyword'} style={{ order: 5 }}>
              <Input.Search
                allowClear
                placeholder={t('common:searchPlaceholder')}
                style={{ width: 240 }}
              />
            </FormItem>
          </ListFilterForm>
        </div>
        {!_.isEmpty(columns) && columns.length > 1 && (
          <div className={'milestonesList'}>
            <UnifiedTableStyle
              rowKey={'id'}
              showNoColumn
              noColumnWidth={80}
