import { ViewEnum } from '@/constants/viewSwitch'
import { useConditionalButton } from '@common/hooks/useConditionalRender'
const { RangePicker } = DatePicker
const FormItem = Form.Item
const ProjectsBudget = () => {
  const tableRef = useRef(null)
  const formRef = useRef(null)
  const [form] = Form.useForm()
  const [visible, setVisible] = useState(false)
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const navigate = useNavigate()
  const checkPermission = useCheckPermission()
  const canProjectBudgetEdit = checkPermission(
    ProjectBudgetPermissionEnum.ProjectBudgetEdit,
  )
  const canAdminUserView = checkPermission(
    ProjectBudgetPermissionEnum.ProjectBudgetAdminUserView,
  )
  const headUserView = checkPermission(
    ProjectBudgetPermissionEnum.ProjectBudgetHeadUserView,
  )
  const canHeadUserView =
    canAdminUserView && headUserView ? false : headUserView
  const { projectsBudgetSearch, setProjectsBudgetSearchInfo } =
    useProjectsBudget()
  const [projectsBudgetFilterParams, setProjectsBudgetFilterParams] =
    useSetState<projectsBudgetSearchState>(projectsBudgetSearchInitData)

  const location = useLocation()
