        'common',
        'strategicObjectives',
        'budget',
        'login',
        'activities',
        'project',
      ])
  const columns: TableColumnProps[] = [
    {
      title: t('budget:columns.projectName'),
      dataIndex: 'name',
      width: 146,
      render: (_, record) => {
        return (
          <div
            onClick={() =>
              jumpToDetailsPage({
                type: 'projectsBudget',
                id: record.id,
                navigate,
              })
            }
            style={{ cursor: 'pointer' }}
          >
            {renderEllipsisText(record.name, underline())}
          </div>
        )
      },
    },
    {
      title: t('budget:columns.objectives'),
      dataIndex: 'objectiveName',
      width: 162,
      render: renderEllipsisText,
    },
    {
      title: t('budget:columns.year'),
      dataIndex: 'startDate',
      width: 74,
      render: (record) => {
        const year = record?.split('/')[2] || ''
        return <div>{year}</div>
      },
    },
    {
      title: t('budget:columns.budget'),
      dataIndex: 'budget',
      width: 133,
      render: (text, record) => {
        return renderEllipsisText(text ? text + ' AED' : 0 + ' AED')
      },
    },
    {
      title: t('budget:columns.actualBudget'),
      dataIndex: 'actualBudget',
      width: 131,
      render: (text, record) => {
        return renderEllipsisText(text ? text + ' AED' : 0 + ' AED')
      },
      // render: renderEllipsisText,
    },
    {
      title: t('budget:columns.expenses'),
      dataIndex: 'expense',
      width: 118,
      render: (text, record) => {
        return renderEllipsisText(text ? text + ' AED' : 0 + ' AED')
      },
    },
    {
      title: t('budget:columns.status'),
      dataIndex: 'status',
      width: 141,
      render: (item, record) => {
        return (
          <Badge
            color={STATUS_COLOR[item]}
            text={t(
              `project:projectReleaseStatus.${PROJECT_RELEASE_STATUS_TEXTS[item]}`,
            )}
          />
        )
      },
    },
    {
      title: t('common:columns.action'),
      fixed: 'right',
      dataIndex: 'action',
      width: 171,
      render: (_, record) => (
        <div>
          <Link
            icon={<IconEye />}
            className='coc-table-link'
            onClick={() => handelProjectDetail(record?.id)}
          >
            {t('common:btn.detail')}
          </Link>
          {record.status !== ProjectReleaseStatusEnum.CLOSED &&
            canProjectBudgetEdit &&
            useConditionalButton(
              <Link
                icon={<IconEdit />}
                className='coc-table-link'
                onClick={() => budgetUpdate(record)}
              >
                {t('common:btn.edit')}
