              record?.cycleStatus,
            )}
        </div>
      ),
    },
  ]
  const [cycleList, setCycleList] = useState([])
  const [selectCycleId, setSelectCycleId] = useState('id')
  const [projectsBudgetId, setProjectsBudgetId] = useState('')
  const [budgetName, setBudgetName] = useState('')
  const [viewEnum, setViewEnum] = useLocalStorageState<any>(
    viewEnumStorageKey,
    {
      defaultValue: ViewEnum.AdminView,
    },
  )
  //获取表格数据
  const getList = useCallback(
    (
      page: { pageNum: number; pageSize: number } = {
        pageNum: projectsBudgetSearch.pageNum,
        pageSize: projectsBudgetSearch.pageSize,
      },
    ) => {
      if (selectCycleId === 'id') {
        return Promise.resolve({ list: [], total: 0 })
      }
      const allSearchFields = {
        cycleId: projectsBudgetSearch.cycleId,
        keyword: projectsBudgetSearch.keyword,
        startDate: projectsBudgetSearch['selectProjectDate']['0'] || '',
        endDate: projectsBudgetSearch['selectProjectDate']['1'] || '',
        userView: viewEnum,
        statusList: [ProjectReleaseStatusEnum.PUBLISHED],
        ...page,
      }
      return projectList(allSearchFields).then((res: any) => {
        res.list = res?.list.map((item) => {
          return {
            ...item,
            name: isLanguageAR ? item?.nameAr : item?.name,
            objectiveName: isLanguageAR
              ? item?.objectiveNameAr
              : item?.objectiveName,
          }
        })
        return res
      })
    },
    [projectsBudgetFilterParams, location],
  )
  const onCancel = () => {
    setVisible(false)
  }
  const onConfirm = () => {
    form.validate().then((values) => {
      setVisible(false)
      const fields = form.getFieldsValue()
      const data = {
        id: projectsBudgetId,
        ...fields,
      }
      updateProjectBudget(data)
    })
  }
  const budgetUpdate = (record: any) => {
    setVisible(true)
    setBudgetName(record?.name)
    setProjectsBudgetId(record?.id)
    form.setFieldValue('budget', record?.budget)
  }

  // 查询cycle列表
  const { run: getCycleByNowTime } = useRequest(getCylceByTime, {
    manual: true,
    onSuccess(data: any, params) {
      const cycleOptions = data.map((item) => ({
        label: isLanguageAR ? item.cycleNameAr : item.cycleName,
        value: item.id,
      }))
      setCycleList(cycleOptions || [])
      if (data.length) {
        const nowCycleId =
          _.isEmpty(projectsBudgetSearch.cycleId) || _.isEmpty(location.state)
            ? cycleOptions[0].value
            : projectsBudgetSearch.cycleId
        formRef.current.setFormItemValue('cycleId', nowCycleId)
        formRef.current?.setFormItemValue(
          'keyword',
          projectsBudgetSearch.keyword,
        )
        formRef.current?.setFormItemValue(
          'selectProjectDate',
          projectsBudgetSearch.selectProjectDate,
        )
        setSelectCycleId(nowCycleId)
        setProjectsBudgetSearchInfo({
          ...projectsBudgetSearch,
          cycleId: nowCycleId,
        })
        setProjectsBudgetFilterParams({ cycleId: nowCycleId })
        // 点击左侧菜单
        if (_.isEmpty(location.state)) {
          setProjectsBudgetSearchInfo({
            ...projectsBudgetSearchInitData,
            cycleId: nowCycleId,
            keyword: '',
          })
          setProjectsBudgetFilterParams({
            ...projectsBudgetSearchInitData,
            cycleId: nowCycleId,
            keyword: '',
          })
          setTimeout(() => {
            formRef.current?.setFormItemValue('keyword', '')
            formRef.current?.setFormItemValue('selectProjectDate', [])
          }, 50)
        }
      }
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })
  const updateHandleDebounce = useDebouncedPromise(projectUpdate, 500)
  const { run: updateProjectBudget, loading: projectsBudgetUpdateLoading } =
    useRequest(updateHandleDebounce, {
      manual: true,
      onSuccess: (res: any) => {
        Message.success(t('strategicObjectives:message.updateSuccess'))
        form.resetFields()
        tableRef.current?.refresh()
      },
    })

  useEffect(() => {
    getCycleByNowTime()
  }, [])

  useEffect(() => {
    setProjectsBudgetSearchInfo({ ...projectsBudgetSearch, userView: viewEnum })
    setProjectsBudgetFilterParams({ userView: viewEnum })
    tableRef.current?.refresh()
  }, [viewEnum])

  const tableChange = (pagination, sorter, filters) => {
    setProjectsBudgetSearchInfo({
      ...projectsBudgetSearch,
      pageNum: pagination.current,
    })
    setProjectsBudgetFilterParams({ pageNum: pagination.current })
  }

  useEffect(() => {
    tableRef.current?.setPageNum(projectsBudgetSearch.pageNum)
  }, [projectsBudgetFilterParams])
  return (
    <PageWrapper
      headerTitle={
        <ViewSwitch
          title={t('budget:projectsBudget')}
          canAdminUserView={canAdminUserView}
          canHeadUserView={canHeadUserView}
          type='project'
          viewEnum={viewEnum}
          setViewEnum={setViewEnum}
        />
      }
    >
      <ListFilterForm
        ref={formRef}
        renderBtnJsx={null}
        showKeywordInput
        onSubmit={(values) => {
          const searchCondition = {
            keyword: values.keyword || '',
            selectProjectDate: values.selectProjectDate || [],
            cycleId: values.cycleId,
            userView: viewEnum,
            pageNum: 1,
            pageSize: 20,
          }
          setProjectsBudgetSearchInfo(searchCondition)
          setProjectsBudgetFilterParams(searchCondition)
          tableRef.current?.refresh()
        }}
      >
        <FormItem field={'selectProjectDate'}>
          <RangePicker
            allowClear
            placeholder={[t('project:startDate'), t('project:endDate')]}
            style={{ width: 240 }}
            format='DD/MM/YYYY'
            onClear={() => {
              setProjectsBudgetSearchInfo({
                ...projectsBudgetSearch,
                selectProjectDate: [],
                pageNum: 1,
              })
              setProjectsBudgetFilterParams({
                selectProjectDate: [],
                pageNum: 1,
              })
            }}
          />
        </FormItem>
        <FormItem field={'cycleId'}>
          <Select
            allowClear
            placeholder={t('activities:selectCycle')}
            style={{ width: 220 }}
            options={cycleList}
            onChange={(value) => {
              setProjectsBudgetSearchInfo({
                ...projectsBudgetSearch,
                cycleId: value,
                pageNum: 1,
              })
              setProjectsBudgetFilterParams({ cycleId: value, pageNum: 1 })
              tableRef.current?.refresh()
            }}
          />
        </FormItem>
      </ListFilterForm>
      <UnifiedTableStyle
        rowKey={'id'}
        showNoColumn
        noColumnWidth={80}
        noColumnFixed='left'
        loading={true}
        ref={tableRef}
        columns={columns}
        getList={getList}
        onChange={tableChange}
      ></UnifiedTableStyle>
      <Modal
        title={t('budget:editProjectNameBudget', { budgetName })}
        visible={visible}
        onCancel={() => setVisible(false)}
        focusLock={false}
        footer={null}
      >
        <Form form={form} layout='vertical'>
          <FormItem
            label={t('budget:budget')}
            field='budget'
            rules={[
              {
                required: true,
                message: t('budget:pleaseEnterBudget'),
              },
            ]}
          >
            <InputNumber
              maxLength={MaxLengthEnum.InputNumber}
              placeholder={t('common:pleaseEnter')}
              suffix='AED'
              min={0}
            ></InputNumber>
          </FormItem>
          <div className='projects-budget-buttons'>
            <Button type='secondary' onClick={onCancel}>
              {t('common:btn.cancel')}
            </Button>
            <Button
              type='primary'
              onClick={onConfirm}
              loading={projectsBudgetUpdateLoading}
            >
              {t('common:btn.confirm')}
            </Button>
          </div>
        </Form>
      </Modal>
    </PageWrapper>
  )
}
