        cycleId: initiativeBudgetSearch.cycleId,
        keyword: initiativeBudgetSearch.keyword,
        startDate: initiativeBudgetSearch.selectInitiativeDate['0'] || '',
        endDate: initiativeBudgetSearch.selectInitiativeDate['1'] || '',
