        res.list = res?.list.filter(
          (item) => item.status != ProjectReleaseStatusEnum.Draft,
        )
        res.list = res?.list.map((item: any) => {
          return {
            ...item,
            name: isLanguageAR ? item?.nameAr : item?.name,
