    run: updateInitiativeBudget,
    loading: initiativesBudgetUpdateLoading,
  } = useRequest(updateHandleDebounce, {
    manual: true,
    onSuccess: (res: any) => {
      Message.success(t('strategicObjectives:message.updateSuccess'))
      form.resetFields()
      tableRef.current?.refresh()
    },
  })
  useEffect(() => {
    setInitiativeBudgetSearchInfo({
      ...initiativeBudgetSearch,
      userView: isUser,
    })
    setInitiativeBudgetFilterParams({ userView: isUser })
    tableRef.current?.refresh()
  }, [isUser])

  useEffect(() => {
    // tableRef.current.refresh()
    tableRef.current?.setPageNum(initiativeBudgetSearch.pageNum)
  }, [initiativeBudgetFilterParams])

  const tableChange = (pagination, sorter, filters) => {
    setInitiativeBudgetSearchInfo({
      ...initiativeBudgetSearch,
      pageNum: pagination.current,
    })
    setInitiativeBudgetFilterParams({ pageNum: pagination.current })
  }
  return (
    <PageWrapper
      headerTitle={
        <ViewSwitch
          title={t('budget:initiativesBudget')}
          canAdminUserView={canAdminUserView}
          canHeadUserView={canHeadUserView}
          setIsUser={setIsUser}
          isUser={isUser}
        />
      }
    >
      <ListFilterForm
        ref={formRef}
        renderBtnJsx={null}
        showKeywordInput
        onSubmit={(values) => {
          const searchCondition = {
            keyword: values.keyword || '',
            selectInitiativeDate: values.selectInitiativeDate || [],
            cycleId: values.cycleId,
            userView: isUser,
            pageNum: 1,
            pageSize: 20,
          }
          setInitiativeBudgetSearchInfo(searchCondition)
          setInitiativeBudgetFilterParams(searchCondition)
          tableRef.current?.refresh()
        }}
      >
        <FormItem field={'selectInitiativeDate'}>
          <RangePicker
            allowClear
            placeholder={[t('project:startDate'), t('project:endDate')]}
            style={{ width: 240 }}
            format='DD/MM/YYYY'
            onClear={() => {
              setInitiativeBudgetSearchInfo({
                ...initiativeBudgetSearch,
                selectInitiativeDate: [],
                pageNum: 1,
              })
              setInitiativeBudgetFilterParams({
                selectInitiativeDate: [],
                pageNum: 1,
              })
            }}
          />
        </FormItem>
        <FormItem field={'cycleId'}>
          <Select
            allowClear
            placeholder={t('project:placeholders.selectCycle')}
            style={{ width: 220 }}
            options={cycleList}
            onChange={(value) => {
              setInitiativeBudgetSearchInfo({
                ...initiativeBudgetSearch,
                cycleId: value,
                pageNum: 1,
              })
              setInitiativeBudgetFilterParams({ cycleId: value, pageNum: 1 })
              tableRef.current?.refresh()
            }}
          />
        </FormItem>
      </ListFilterForm>
      <UnifiedTableStyle
        rowKey={'id'}
        showNoColumn
        noColumnWidth={80}
        noColumnFixed='left'
        loading={true}
        ref={tableRef}
        columns={columns}
        getList={getList}
        onChange={tableChange}
      ></UnifiedTableStyle>
      <Modal
        title={t('budget:editInitiativesNameBudget', { budgetName })}
        visible={visible}
        onCancel={() => setVisible(false)}
        focusLock={false}
        footer={null}
      >
        <Form form={form} layout='vertical'>
          <FormItem
            label={t('budget:budget')}
            field={'budget'}
            rules={[
              {
                required: true,
                message: t('budget:pleaseEnterBudget'),
              },
            ]}
          >
            <InputNumber
              maxLength={MaxLengthEnum.InputNumber}
              placeholder={t('common:pleaseEnter')}
              suffix='AED'
              min={0}
            ></InputNumber>
          </FormItem>
          <div className='initiatives-budget-buttons'>
            <Button type='secondary' onClick={onCancel}>
              {t('common:btn.cancel')}
            </Button>
            <Button
              type='primary'
              onClick={onConfirm}
              loading={initiativesBudgetUpdateLoading}
            >
              {t('common:btn.confirm')}
            </Button>
          </div>
        </Form>
      </Modal>
    </PageWrapper>
  )
}
