const AddInitiativesBtn = ({ exportParams }: AddInitiativesBtnProps) => {
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['initiatives', 'common'])
  const navigate = useNavigate()
  const { pageSize: pageCount } = exportParams
  const { run: exportList, loading: exportLoading } = useRequest(
    exportInitiativeListRequest,
