        pageNum: initiativeSearch.pageNum,
      }
      return initiativeList(allSearchFields).then((res: any) => {
        setTotalNumber(res?.total)
        return {
          list: res?.list,
          total: res?.total,
          pageNum: initiativeSearch?.pageNum,
          pageSize: initiativeSearch.pageSize,
        }
      })
    },
    [
      runInitiativeDelete,
      location,
      filterInitiativeParams,
      deleteLoading,
      selectCycleId,
    ],
  )
  const tableChange = (pagination, sorter, filters) => {
    setInitiativeFilterInfo({
      ...initiativeSearch,
      pageNum: pagination.current,
      pageSize: pagination.pageSize,
    })
    setFilterInitiativeParams({ pageNum: pagination.current })
  }

  const handelInitiativeEdit = (id, completionStatus, needApproval) => {
    if (needApproval) {
      navigate(`/initiatives/initiatives-mgmt/edit/3/${id}`)
    } else {
      if (completionStatus === INITIATIVES_COMPLETION_STATUS.StepOne) {
        navigate(`/initiatives/initiatives-mgmt/edit/1/${id}`)
      }
      if (completionStatus === INITIATIVES_COMPLETION_STATUS.StepTwo) {
        navigate(`/initiatives/initiatives-mgmt/edit/2/${id}`)
      }
      if (completionStatus === INITIATIVES_COMPLETION_STATUS.StepThree) {
        navigate(`/initiatives/initiatives-mgmt/edit/3/${id}`)
      }
    }
  }

  const handelAdminEditInitiative = (id: string) => {
    navigate(`/initiatives/initiatives-mgmt/edit/1/${id}`, {
      state: { isAdminPublishedEdit: true, locationFrom: 'initiatives' },
    })
  }
  const handleSelectChange = (value) => {
    setInitiativeFilterInfo({
      ...initiativeSearch,
      cycleId: value,
      orgId: '',
      pageNum: 1,
    })
    setFilterInitiativeParams({ cycleId: value, orgId: '', pageNum: 1 })
    getOrgTree({ cycleId: value })
    tableRef.current?.refresh()
  }

  useEffect(() => {
    setInitiativeFilterInfo({ ...initiativeSearch, viewType: viewEnum })
    setFilterInitiativeParams({ viewType: viewEnum })
    tableRef.current?.refresh()
  }, [viewEnum])

  useEffect(() => {
    tableRef.current?.setPageNum(initiativeSearch.pageNum)
  }, [initiativeSearch])

  //获取department 列表
  const { run: getOrgTree } = useRequest(getOrgTreeRecursion, {
    manual: true,
    onSuccess(res: any, params) {
      formRef?.current?.setFormItemValue('orgId', undefined)
      const data = transformData(res, t)
      setDepartmentData(data || [])
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })
  useEffect(() => {
    getProjectTableConfig(TableBizType.Initiative)
  }, [])
  const departmentNameChange = (value) => {
    setInitiativeFilterInfo({
      ...initiativeSearch,
      orgId: value,
      pageNum: 1,
    })
    setFilterInitiativeParams({
      orgId: value,
      pageNum: 1,
    })
    tableRef.current?.refresh()
  }

  const [columns, setColumns] = useState([])
  //渲染checkbox组件的数据
  const [columnsSetting, setColumnsSetting] = useState([])
  const [visibleColumnsDataIndex, setVisibleColumnsDataIndex] = useState([])
  const [columnsFromServer, setColumnsFromServer] = useState([])
  const [actionData, setActionData] = useState([])
  const [popVisible, setPopVisible] = useState(false)

  const { run: getProjectTableConfig } = useRequest(getUserTableHeaderConfig, {
    manual: true,
    onSuccess(data: any, params) {
      const getColumnsFromServer = JSON.parse(data) ?? []
      if (!_.isEmpty(getColumnsFromServer)) {
        const columnServerData = columnsData.filter((item) =>
          getColumnsFromServer.includes(item.dataIndex as string),
        )
        setColumnsFromServer(getColumnsFromServer)
        setColumns(columnServerData)
        setVisibleColumnsDataIndex(getColumnsFromServer)
      } else {
        const visibleColumnsDataIndex = columnsData
          .filter((v) => v.dataIndex !== 'action')
          .map((m) => m.dataIndex as string)
        setTimeout(() => {
          setColumns(columnsData)
        }, 10)
        setColumnsFromServer(visibleColumnsDataIndex)
      }
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })
  useEffect(() => {
    // 需要配置的字段
    const columnsSettingData = columnsData
      .filter((m) => m.dataIndex !== 'action')
      .map((v) => ({ key: v.dataIndex as string, title: v.title }))
    setColumnsSetting(columnsSettingData)
    const actions = columnsData.filter((m) => m.dataIndex === 'action')
    setActionData(actions)
    // 需要配置字段的索引
    const visibleColumnsDataIndex = columns
      .filter((m) => m.dataIndex !== 'action')
      .map((m) => m.dataIndex as string)
    setVisibleColumnsDataIndex(visibleColumnsDataIndex)
  }, [t('initiatives:initiativeTableColumns.name')])

  // 渲染展示的表头，根据dataIndex 选择的变化进行渲染
  useEffect(() => {
    const showColumns = columnsData
      .filter((item) => item.dataIndex !== 'action')
      .filter((item) =>
        visibleColumnsDataIndex.includes(item.dataIndex as string),
      )
    setColumns([...showColumns, ...actionData])
  }, [visibleColumnsDataIndex])

  useEffect(() => {
    if (viewEnum == ViewEnum.UserView) {
      setInitiativeFilterInfo({
        ...initiativeSearch,
        ownerName: '',
        orgId: '',
        pageNum: 1,
      })
      setFilterInitiativeParams({
        ownerName: '',
        orgId: '',
        pageNum: 1,
      })
      formRef.current.setFormItemValue('ownerName', undefined)
      formRef.current.setFormItemValue('orgId', undefined)
    }
  }, [viewEnum])

  return (
    <div className={'page-wrapper-box'}>
      <PageWrapper
        headerTitle={
          <ViewSwitch
            title={t('initiatives:upperTitle')}
            canAdminUserView={canAdminUserView}
            canHeadUserView={canHeadUserView}
            canInitiativeCreatorView={canInitiativeAdd}
            setViewEnum={setViewEnum}
            viewEnum={viewEnum}
            type={'initiative'}
          />
        }
      >
        <ListFilterForm
          ref={formRef}
          renderBtnJsx={
            <AddInitiativesBtn
              exportParams={{
                // ...tablePageParams,
                pageNum: 1,
                pageSize: +totalNumber,
                startDate: initiativeSearch['selectInitiativesDate']?.length
                  ? initiativeSearch['selectInitiativesDate'][0]
                  : undefined,
                endDate: initiativeSearch['selectInitiativesDate']?.length
                  ? initiativeSearch['selectInitiativesDate'][1]
                  : undefined,
                cycleId: initiativeSearch.cycleId,
                ownerName: initiativeSearch.ownerName,
                keyword: initiativeSearch.keyword,
                orgId: initiativeSearch.orgId,
                viewType: viewEnum,
              }}
            />
          }
          onSubmit={(values) => {
            setInitiativeFilterInfo({
              keyword: values.keyword,
              cycleId: values.selectInitiativesCycle || '',
              ownerName: values.ownerName || '',
              orgId: values?.orgId,
              selectInitiativesDate: values.selectInitiativesDate || [],
              viewType: viewEnum,
              pageNum: 1,
              pageSize: 20,
            })
            setFilterInitiativeParams({
              keyword: values.keyword,
              cycleId: values.selectInitiativesCycle || '',
              ownerName: values.ownerName || '',
              orgId: values?.orgId,
              selectInitiativesDate: values.selectInitiativesDate || [],
              viewType: viewEnum,
              pageNum: 1,
              pageSize: 20,
            })
            tableRef.current?.refresh()
          }}
          showResetBtn={true}
          onReset={() => {
            formRef.current.resetForm()
            setInitiativeFilterInfo({
              ...InitiativeFilterInitData,
            })
            setFilterInitiativeParams({
              ...InitiativeFilterInitData,
            })
          }}
          renderSettingJsx={
            <PopSetting
              visibleColumns={columnsSetting}
              setVisibleColumnsDataIndex={setVisibleColumnsDataIndex}
              setPopVisible={setPopVisible}
              columnsFromServer={columnsFromServer}
              setColumnsFromServer={setColumnsFromServer}
              disableFiled={['name']}
              bizType={TableBizType.Initiative}
            />
          }
          showSettingBtn={true}
          popVisible={popVisible}
          setPopVisible={setPopVisible}
        >
          <FormItem field={'selectInitiativesDate'}>
            <RangePicker
              allowClear
              placeholder={[
                t('initiatives:initiativeInfo.initiativeStartDate'),
                t('initiatives:initiativeInfo.initiativeEndDate'),
              ]}
              style={{ width: 240 }}
              format='DD/MM/YYYY'
              onClear={() => {
                setInitiativeFilterInfo({
                  ...initiativeSearch,
                  selectInitiativesDate: [],
                  pageNum: 1,
                })
                setFilterInitiativeParams({
                  selectInitiativesDate: [],
                  pageNum: 1,
                })
              }}
            />
          </FormItem>
          <FormItem field={'selectInitiativesCycle'}>
            <Select
              onChange={handleSelectChange}
              placeholder={t('common:pleaseSelect')}
              style={{ width: 240 }}
              options={cylceList}
            />
          </FormItem>
          {permissionJudgment('admin_or_initiativeAdmin_or_sector') &&
            viewEnum != ViewEnum.UserView && (
              <FormItem field={'ownerName'}>
                <Select
                  placeholder={t(
                    'initiatives:placeholders.enterInitiativeOwnerName',
                  )}
                  options={userList}
                  allowClear
                  showSearch
                  filterOption={(inputValue, option) =>
                    option.props.value
                      .toLowerCase()
                      .indexOf(inputValue.toLowerCase()) >= 0 ||
                    option.props.children
                      .toLowerCase()
                      .indexOf(inputValue.toLowerCase()) >= 0
                  }
                  style={{ width: 240 }}
                  onChange={(value) => {
                    setInitiativeFilterInfo({
                      ...initiativeSearch,
                      ownerName: value,
                      pageNum: 1,
                    })
                    setFilterInitiativeParams({ ownerName: value, pageNum: 1 })
                    tableRef.current?.refresh()
                  }}
                />
              </FormItem>
            )}
          {permissionJudgment('admin_or_initiativeAdmin') &&
            viewEnum != ViewEnum.UserView && (
              <FormItem field={'orgId'}>
                <TreeSelect
                  showSearch={true}
                  placeholder={t('membersDepartments:columns.departmentName')}
                  allowClear={true}
                  treeData={departmentData}
                  onChange={departmentNameChange}
                  treeProps={{
                    onSelect: (v, n) => {
                      console.log(n)
                    },
                  }}
                  filterTreeNode={(inputText, node) => {
                    return (
                      node.props.title
                        .toLowerCase()
                        .indexOf(inputText.toLowerCase()) > -1
                    )
                  }}
                  style={{ width: 240 }}
                />
              </FormItem>
            )}

          <FormItem field={'keyword'}>
            <Input.Search
              allowClear
              placeholder={t('common:searchPlaceholder')}
              style={{ width: 240 }}
            />
          </FormItem>
        </ListFilterForm>
        {!_.isEmpty(columns) && columns.length > 1 && (
          <UnifiedTableStyle
            rowKey={'name'}
            showNoColumn
            noColumnWidth={80}
            noColumnFixed='left'
            loading={true}
            ref={tableRef}
            columns={columns}
            getList={getList}
            onChange={tableChange}
          ></UnifiedTableStyle>
        )}

        <InitiativesDeleteModal
          deleteModalVisible={deleteModalVisible}
          setDeleteVisible={setDeleteVisible}
        />
      </PageWrapper>
    </div>
  )
}
export default InitiativesMgmt

import { useCallback } from 'react'
import { useSelector } from 'react-redux'
import { RootState } from '@/store'
import { UserState } from '@common/store/slices/user'
import { isCheckPermissionEnabled } from '@common/constants/env'

// 根据后端返回的权限标识，check当前用户是否有权限
function useCheckPermission() {
  const { userRoleBtnMenuList } = useSelector<RootState, UserState>(
    (state) => state.user,
  )

  return useCallback(
    (permission: string | string[]) => {
      if (!isCheckPermissionEnabled) return true

      const arr = Array.isArray(permission) ? permission : [permission]
      const flags = []
      arr.forEach((v) => {
        if (userRoleBtnMenuList.includes(v)) {
          flags.push(v)
        }
      })
      //  只要存在一个权限以上就显示
      return flags.some(Boolean)
    },
    [userRoleBtnMenuList],
  )
}

export default useCheckPermission

